INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('c950ba90-d48f-55e1-bfbb-167854dfe935', 'arabic-4eme', 'النعت والتطابق (الصفة)', 'نتعرّف النعت (الصفة) الذي يصف اسمًا قبله ويبيّن صفةً من صفاته، ونتعلّم كيف يتبع النعت منعوته في التذكير والتأنيث والإفراد والجمع والتعريف والتنكير والحركة.', '# ⚔️ النعت والتطابق (الصفة) — مرآةُ الاسم

> 💡 «الصفةُ مرآةٌ للاسم: كما يكون الموصوفُ تكون صفتُه!»

عرفنا الجملة وركنيها، واليوم نتعلّم كيف **نزيّن الأسماء** بصفاتٍ تصفها. هذه الصفة تُسمّى **النعت**، وسرُّها الكبير أنّها **تطابق** الاسم الذي تصفه. من أتقن المطابقة كتبَ كلامًا سليمًا لا خطأ فيه.

## 🏰 ما النعت (الصفة)؟

**النعت** كلمةٌ تصف اسمًا قبلها وتبيّن صفةً من صفاته. والاسم الموصوف يُسمّى **المنعوت** (أو الموصوف).

- في *«ولدٌ مجتهدٌ»*: «ولدٌ» منعوتٌ، و«مجتهدٌ» نعتٌ يصفه.
- في *«حديقةٌ جميلةٌ»*: «حديقةٌ» منعوتٌ، و«جميلةٌ» نعتٌ يصفها.

النعت يجيب عن السؤال: **كيف هو المنعوت؟** فنقول: الوردةُ… كيف هي؟ **حمراءُ**.

## 🛡️ السرّ الأكبر: النعت يتبع منعوته

النعت لا يسير وحده، بل **يتبع منعوته ويطابقه**. هذه المطابقة في **أربعة أمورٍ** نتعلّمها واحدًا واحدًا.

| المنعوت | النعت | نوع التطابق |
| --- | --- | --- |
| ولدٌ | مجتهدٌ | تذكير |
| بنتٌ | مجتهدةٌ | تأنيث |
| الكتابُ | المفيدُ | تعريف |
| كتبٌ | مفيدةٌ | جمع |

## 🔮 المطابقة في التذكير والتأنيث

إن كان المنعوت **مذكّرًا** كان النعت **مذكّرًا**، وإن كان **مؤنّثًا** كان النعت **مؤنّثًا** (نزيد عليه غالبًا **تاءً مربوطةً**).

- *«ولدٌ مجتهدٌ»* (مذكّر) — *«بنتٌ مجتهدةٌ»* (مؤنّث).
- *«بحرٌ واسعٌ»* (مذكّر) — *«حديقةٌ واسعةٌ»* (مؤنّث).

## 🧮 المطابقة في الإفراد والجمع

إن كان المنعوت **مفردًا** كان النعت مفردًا، وإن كان **جمعًا** طابقه. ومن قواعدنا: جمعُ غير العاقل (الأشياء) يُوصف بصفةٍ **مفردةٍ مؤنّثةٍ**.

- *«كتابٌ مفيدٌ»* (مفرد) — *«كتبٌ مفيدةٌ»* (جمع أشياء).
- *«تلميذٌ مجتهدٌ»* (مفرد) — *«تلاميذُ مجتهدون»* (جمع عاقل).

## 🧭 المطابقة في التعريف والتنكير

إن كان المنعوت **معرفةً** (فيه «الـ») كان النعت معرفةً مثله، وإن كان **نكرةً** كان النعت نكرةً.

- *«الولدُ المجتهدُ»* (معرفة) — *«ولدٌ مجتهدٌ»* (نكرة).
- *«القمرُ المنيرُ»* (معرفة) — *«قمرٌ منيرٌ»* (نكرة).

> 🗡️ حيلةٌ سريعة: انظر إلى المنعوت أوّلًا (مذكّر أم مؤنّث؟ مفرد أم جمع؟ معرفة أم نكرة؟)، ثمّ **اجعل النعت مثله تمامًا**، وامنحه **الحركة نفسها**: «رأيتُ الوردةَ الجميلةَ» (نصبٌ يتبع نصبًا).

> ⚠️ الفخّ الشائع: أن نصف اسمًا مؤنّثًا بصفةٍ مذكّرةٍ! نقول *«الوردةُ الجميلةُ»* ولا نقول *«الوردةُ الجميلُ»*، لأنّ «الوردة» مؤنّثةٌ فلا بدّ أن تكون صفتُها مؤنّثةً.

> 🏆 رائع! صرتَ تصف الأسماء بنعوتٍ مطابقةٍ سليمةٍ. في الفصل القادم نتعلّم **أدوات الربط** التي تصل الكلمات والجمل بعضها ببعض!', '# 📜 ملخّص: النعت والتطابق (الصفة)

- **النعت** (الصفة) كلمةٌ تصف اسمًا قبلها وتبيّن صفةً من صفاته، والاسم الموصوف يُسمّى **المنعوت**.
- **القاعدة الكبرى:** النعت **يتبع منعوته ويطابقه** في أربعة أمورٍ.
- **التذكير والتأنيث:** «ولدٌ مجتهدٌ» (مذكّر) / «بنتٌ مجتهدةٌ» (مؤنّث، بزيادة تاءٍ مربوطةٍ غالبًا).
- **الإفراد والجمع:** «كتابٌ مفيدٌ» (مفرد) / «كتبٌ مفيدةٌ» (جمع الأشياء يُوصف بمفردٍ مؤنّثٍ).
- **التعريف والتنكير:** «الولدُ المجتهدُ» (معرفة) / «ولدٌ مجتهدٌ» (نكرة).
- **الحركة (الإعراب):** النعت يأخذ حركة منعوته (رفعًا ونصبًا وجرًّا): «الوردةَ الجميلةَ».
- **الفخّ:** لا نصف مؤنّثًا بصفةٍ مذكّرةٍ؛ نقول «الوردةُ الجميلةُ» لا «الوردةُ الجميلُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('cd792bd7-06ae-50eb-811e-0fc4ddc757ed', 'arabic-4eme', 'أدوات الربط وحروف الجرّ', 'نتعرّف حروف الجرّ (في، على، إلى، من، عن، الباء، اللام، الكاف) التي تربط الكلمات وتجرّ الاسم بعدها، وأدوات العطف (الواو، الفاء، ثمّ) التي تربط بين الكلمات والجمل، ونلاحظ علامة الجرّ (الكسرة) على الاسم المجرور.', '# ⚔️ أدوات الربط وحروف الجرّ — جسورُ الكلام

> 💡 «الكلماتُ جزرٌ، وأدواتُ الربط جسورٌ تصلها… فمن بنى الجسر وصلَ المعنى!»

عرفنا كيف نبني الجملة وأركانها. واليوم نتعلّم **الجسور** التي تربط الكلمات والجمل بعضها ببعض: **حروف الجرّ** و**أدوات العطف**. بها يصير كلامنا متماسكًا يمشي كالقافلة المنظّمة.

## 🏰 ما حروف الجرّ؟

**حروف الجرّ** حروفٌ تأتي قبل الاسم فتربطه بما قبله، و**تجرّ** الاسمَ بعدها؛ أي تجعل آخره **مكسورًا** غالبًا. وأشهرها:

**مِن، إلى، عن، على، في، الباء (بـ)، اللام (لـ)، الكاف (كـ).**

- *«ذهبتُ إلى المدرسةِ.»* ← «إلى» حرف جرّ، و«المدرسةِ» اسمٌ مجرورٌ بالكسرة.
- *«جلستُ على الكرسيِّ.»* ← «على» حرف جرّ، و«الكرسيِّ» مجرور.

## 🛡️ علامة الجرّ: الكسرة

الاسم الذي يأتي بعد حرف الجرّ يُسمّى **الاسم المجرور**، وعلامة جرّه الأصليّة **الكسرة** على آخره.

| الجملة | حرف الجرّ | الاسم المجرور |
| --- | --- | --- |
| خرجَ من البيتِ. | من | البيتِ |
| سافرَ إلى تونسَ. | إلى | تونسَ |
| كتبتُ بالقلمِ. | الباء | القلمِ |

> 🗡️ حيلةٌ سريعة: إذا رأيتَ حرف جرٍّ (في، على، إلى…) فاعلمْ أنّ الاسم بعده **مجرورٌ**، وآخره **كسرةٌ** غالبًا.

## 🔮 معاني بعض حروف الجرّ

كلّ حرفٍ يحمل معنًى يوضّح العلاقة:

- **في** للظرفيّة (المكان أو الزمان): *«الكتابُ في الحقيبةِ.»*
- **على** للاستعلاء (فوق): *«القطّةُ على السطحِ.»*
- **إلى** لانتهاء الغاية: *«مشى إلى النهرِ.»*
- **من** لابتداء الغاية: *«عادَ من السوقِ.»*
- **الباء** للاستعانة (الأداة): *«قطعَ بالسكّينِ.»*

## 🧮 أدوات العطف: الواو والفاء وثمّ

**أدوات العطف** تربط بين كلمتين أو جملتين، فيشترك المعطوفُ مع ما قبله في الحكم:

- **الواو** للجمع المطلق: *«جاءَ سعدٌ وخالدٌ.»* (معًا، دون ترتيب).
- **الفاء** للترتيب مع التعقيب (بلا مهلة): *«دخلَ المعلّمُ فوقفَ التلاميذُ.»*
- **ثمّ** للترتيب مع المهلة (بعد حين): *«زرعَ الحبَّ ثمّ حصدَ الثمرَ.»*

| الأداة | المعنى | مثال |
| --- | --- | --- |
| الواو | الجمع | أكلتُ تفّاحةً وموزةً. |
| الفاء | ترتيبٌ وتعقيب | سمعَ النداءَ فأجابَ. |
| ثمّ | ترتيبٌ ومهلة | تعلّمَ الحروفَ ثمّ قرأَ. |

> ⚠️ الفخّ الشائع: لا تخلط بين **الواو** و**الفاء** و**ثمّ**! «الواو» لا ترتيب فيها، و«الفاء» ترتيبٌ سريع، و«ثمّ» ترتيبٌ مع تراخٍ ومُهلة. اختر الأداة حسب المعنى الذي تريده.

## 🧭 كيف نستعمل الجسور؟

1. إذا أردتَ ربط اسمٍ بمكانٍ أو أداةٍ أو غاية ← استعمل **حرف جرٍّ** مناسبًا، واكسرْ آخر الاسم بعده.
2. إذا أردتَ ربط شيئين أو حدثين ← استعمل **أداة عطفٍ** حسب المعنى (جمعٌ، أو ترتيبٌ سريع، أو ترتيبٌ بمهلة).

> 🏆 رائع! صرتَ تبني جسور الكلام بحروف الجرّ وأدوات العطف، وتضبط الاسم المجرور بالكسرة. في الفصل القادم ندخل عالم **الزمن** ونصرّف الفعل بين الماضي والمضارع والأمر!', '# 📜 ملخّص: أدوات الربط وحروف الجرّ

- **حروف الجرّ** حروفٌ تأتي قبل الاسم فتربطه بما قبله وتجرّه: **مِن، إلى، عن، على، في، الباء، اللام، الكاف**.
- **علامة الجرّ** الكسرة على آخر الاسم المجرور: «خرجَ من البيتِ.» ← «البيتِ» مجرورٌ بالكسرة.
- **معاني الحروف:** «في» للظرفيّة، «على» للاستعلاء، «إلى» لانتهاء الغاية، «من» لابتدائها، «الباء» للاستعانة.
- **أدوات العطف** تربط بين كلمتين أو جملتين: **الواو** (جمعٌ بلا ترتيب)، **الفاء** (ترتيبٌ وتعقيب سريع)، **ثمّ** (ترتيبٌ مع مهلة).
- مثال: «جاءَ سعدٌ وخالدٌ» (معًا)، «دخلَ فوقفَ» (تعقيب)، «زرعَ ثمّ حصدَ» (مهلة).
- **الفخّ:** لا نخلط الواو (لا ترتيب) بالفاء (ترتيبٌ سريع) بثمّ (ترتيبٌ مع تراخٍ).', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('76e9daaa-eb20-58c8-ac32-7c74c36b98f0', 'arabic-4eme', 'أزمنة الفعل: الماضي والمضارع والأمر', 'نتعرّف أقسام الفعل بحسب زمنه: الفعل الماضي (حدثٌ مضى)، والفعل المضارع (حدثٌ يجري أو سيجري)، وفعل الأمر (طلبُ حدوث الشيء)، ونميّز علاماتها ونصرّف الفعل بينها.', '# ⚔️ أزمنة الفعل: الماضي والمضارع والأمر — آلةُ الزمن

> 💡 «الفعلُ مسافرٌ في الزمن: مرّةً يحكي ما مضى، ومرّةً ما يجري، ومرّةً يأمر بما سيكون!»

عرفنا أنّ الفعل يدلّ على **حدثٍ مقترنٍ بزمن**. واليوم نركب **آلة الزمن** لنرى الفعل في أزمنته الثلاثة: **الماضي**، و**المضارع**، و**الأمر**. من عرف زمن الفعل أتقن صرفه.

## 🏰 الفعل الماضي

**الفعل الماضي** يدلّ على حدثٍ **وقعَ وانتهى قبل زمن التكلّم**.

- *«كتبَ التلميذُ.»* — *«لعبَ الأطفالُ أمسِ.»* — *«سافرَ أبي.»*

علامته: يُقبل دخولُ تاء التأنيث الساكنة عليه مع الفاعل المؤنّث: *«كتبتْ، لعبتْ»*، ويُبنى آخرُه على الفتح غالبًا: *«كتبَ»*.

## ⚡ الفعل المضارع

**الفعل المضارع** يدلّ على حدثٍ **يجري الآن أو سيجري** (الحاضر أو المستقبل).

علامته أنّه **يبدأ بحرفٍ من حروف المضارعة** المجموعة في كلمة **«أنيت»**: **الهمزة (أ)، النون (ن)، الياء (ي)، التاء (ت)**.

| حرف المضارعة | المثال | الدلالة |
| --- | --- | --- |
| أ | أكتبُ | المتكلّم (أنا) |
| ن | نكتبُ | المتكلّمون (نحن) |
| ي | يكتبُ | الغائب (هو) |
| ت | تكتبُ | المخاطَب/الغائبة (أنتَ/هي) |

> 🗡️ حيلةٌ سريعة: إن بدأ الفعلُ بأحد حروف **«أنيت»** فهو **مضارعٌ**: «يلعبُ، تشربُ، أقرأُ، نذهبُ».

## 🛡️ فعل الأمر

**فعل الأمر** يدلّ على **طلبِ حدوث الشيء** في المستقبل، ويكون موجّهًا للمخاطَب.

- *«اكتبْ درسَكَ.»* — *«العبْ بهدوءٍ.»* — *«اقرأْ بتمعّنٍ.»*

علامته: يدلّ على الطلب، ويُقبل أن تلحقه ياءُ المخاطبة: *«اكتبي، العبي»*، وآخرُه ساكنٌ غالبًا: *«اكتبْ»*.

## 🔮 جدول الأزمنة الثلاثة

نأخذ فعلًا واحدًا ونصرّفه في الأزمنة الثلاثة:

| الماضي | المضارع | الأمر |
| --- | --- | --- |
| كتبَ | يكتبُ | اكتبْ |
| جلسَ | يجلسُ | اجلسْ |
| فتحَ | يفتحُ | افتحْ |
| سمعَ | يسمعُ | اسمعْ |

> ⚠️ الفخّ الشائع: لا تحكم بالزمن من المعنى وحده، بل انظر إلى **شكل الفعل وعلامته**: «يلعبُ» مضارعٌ (بدأ بالياء) حتى لو قُصد به المستقبل، و«العبْ» أمرٌ (طلبٌ) لا مضارع.

## 🧮 كيف نحوّل بين الأزمنة؟

1. من **الماضي** إلى **المضارع**: ضع حرف مضارعةٍ مناسبًا في أوّله واكسر بنيته على المضارع: *«شربَ ← يشربُ»*.
2. من **المضارع** إلى **الأمر**: احذف حرف المضارعة واطلبْ به: *«تكتبُ ← اكتبْ»*.

> 🏆 رائع! صرتَ تميّز الماضي والمضارع والأمر بعلاماتها وتصرّف الفعل بينها. في الفصل القادم نفتح باب **الإملاء** ونتعلّم رسم الهمزة في أوّل الكلمة والتنوين!', '# 📜 ملخّص: أزمنة الفعل: الماضي والمضارع والأمر

- **الفعل الماضي** يدلّ على حدثٍ وقعَ وانتهى قبل التكلّم: «كتبَ، لعبَ»، وتلحقه تاءُ التأنيث مع الفاعل المؤنّث «كتبتْ».
- **الفعل المضارع** يدلّ على حدثٍ يجري الآن أو سيجري، ويبدأ بحرفٍ من حروف المضارعة المجموعة في **«أنيت»**: أ، ن، ي، ت («أكتبُ، نكتبُ، يكتبُ، تكتبُ»).
- **فعل الأمر** يدلّ على طلبِ حدوث الشيء: «اكتبْ، اقرأْ»، وتلحقه ياءُ المخاطبة «اكتبي».
- **التصريف:** كتبَ ← يكتبُ ← اكتبْ، وجلسَ ← يجلسُ ← اجلسْ.
- **التحويل:** من الماضي للمضارع نزيد حرف مضارعة («شربَ ← يشربُ»)، ومن المضارع للأمر نحذفه ونطلب («تكتبُ ← اكتبْ»).
- **الفخّ:** نحكم بالزمن من شكل الفعل وعلامته لا من المعنى وحده.', 6)
