INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('404f9597-6d97-566e-846f-d8b4c8dd4673', '8ec361a3-5b14-552b-8fe9-0ac41236f396', 'أيّ جملةٍ ممّا يلي فعليةٌ؟', '[{"id":"a","text":"البستانيُّ نشيطٌ."},{"id":"b","text":"يسقي البستانيُّ الأشجارَ."},{"id":"c","text":"البستانُ أخضرُ."},{"id":"d","text":"الأشجارُ عاليةٌ."}]'::jsonb, 'b', '«يسقي البستانيُّ الأشجارَ.» بدأت بالفعل «يسقي» فهي فعلية، أمّا البقيّة فبدأت بأسماءٍ فهي اسمية.', 4)
