  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02b81fb3-e8d9-5215-bb27-fe79d2d777b9', '8ec361a3-5b14-552b-8fe9-0ac41236f396', 'حوّل الجملة الاسمية «الطائرُ يبني عشَّهُ.» إلى جملةٍ فعليةٍ بالبدء بالفعل:', '[{"id":"a","text":"عشَّهُ الطائرُ يبني."},{"id":"b","text":"الطائرُ عشَّهُ يبني."},{"id":"c","text":"يبني عشَّهُ الطائرُ."},{"id":"d","text":"يبني الطائرُ عشَّهُ."}]'::jsonb, 'd', 'نبدأ بالفعل «يبني» ثمّ الفاعل «الطائرُ» ثمّ المفعول «عشَّهُ»، فتصير فعليةً مرتّبة: «يبني الطائرُ عشَّهُ.»', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1739080d-dae9-580d-9dfc-4828adbdfbeb', '8ec361a3-5b14-552b-8fe9-0ac41236f396', 'قال تلميذٌ: «كلّ جملةٍ فيها اسمٌ فهي اسمية». ما الصحيح؟', '[{"id":"a","text":"صحيح، وجود الاسم يكفي"},{"id":"b","text":"صحيح، الأسماء أهمّ من الأفعال"},{"id":"c","text":"خطأ؛ العبرة بأوّل كلمةٍ: فعلٌ ← فعلية، اسمٌ ← اسمية"},{"id":"d","text":"خطأ؛ كلّ جملةٍ اسمية دائمًا"}]'::jsonb, 'c', 'الخطأ الشائع: الحكم بوجود الاسم. نوع الجملة يُحدَّد بأوّل كلمةٍ فيها؛ «يأكلُ الولدُ التفّاحةَ» فعليةٌ رغم كثرة أسمائها لأنّها بدأت بفعل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

