INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b58c634-ba27-5c5d-80d8-6f03e8df690d', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'اقرأ: «هطلَ المطرُ. الأرضُ خضراءُ.» كم جملةً في النصّ؟', '[{"id":"a","text":"جملةٌ واحدة"},{"id":"b","text":"جملتان"},{"id":"c","text":"ثلاث جمل"},{"id":"d","text":"لا جملة"}]'::jsonb, 'b', 'كلّ جملةٍ تنتهي بنقطة؛ هنا نقطتان فالجمل اثنتان: «هطلَ المطرُ.» و«الأرضُ خضراءُ.»', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e154f9f5-dc27-5789-89e3-a8da30e31e67', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'من الجملتين السابقتين، أيّهما فعليةٌ؟', '[{"id":"a","text":"الأرضُ خضراءُ."},{"id":"b","text":"الجملتان اسميتان"},{"id":"c","text":"هطلَ المطرُ."},{"id":"d","text":"لا فعلية فيهما"}]'::jsonb, 'c', '«هطلَ المطرُ.» بدأت بالفعل «هطلَ» فهي فعلية، و«الأرضُ خضراءُ.» بدأت باسمٍ فهي اسمية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9794de11-9bb3-5e23-9bb6-bf42576d0e91', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'أكمل الجملة الاسمية بخبرٍ مناسب: «العسلُ ___.»', '[{"id":"a","text":"يجري"},{"id":"b","text":"تحتَ الطاولةِ فوقَ"},{"id":"c","text":"أزرقُ يطيرُ"},{"id":"d","text":"حلوٌ"}]'::jsonb, 'd', '«حلوٌ» خبرٌ يصف العسل ويتمّ به المعنى: «العسلُ حلوٌ.»، أمّا البقيّة فلا تناسبه أو ليست خبرًا مفردًا واضحًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b7f9a99-00be-56e4-b34b-909b0349c2fc', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'في الجملة «يطبخُ الطبّاخُ الطعامَ.»، عيّن المسند (الفعل):', '[{"id":"a","text":"يطبخُ"},{"id":"b","text":"الطبّاخُ"},{"id":"c","text":"الطعامَ"},{"id":"d","text":"لا فعل فيها"}]'::jsonb, 'a', '«يطبخُ» هو المسند (الفعل) الدالّ على الحدث، و«الطبّاخُ» مسندٌ إليه (فاعل) و«الطعامَ» مفعولٌ به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2031494-59df-5084-95fc-095747d6d4d4', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'صنّف: «الشمسُ مشرقةٌ.» و«أشرقتِ الشمسُ.»', '[{"id":"a","text":"كلتاهما فعلية"},{"id":"b","text":"كلتاهما اسمية"},{"id":"c","text":"الأولى اسمية والثانية فعلية"},{"id":"d","text":"الأولى فعلية والثانية اسمية"}]'::jsonb, 'c', '«الشمسُ مشرقةٌ.» بدأت باسمٍ فهي اسمية، و«أشرقتِ الشمسُ.» بدأت بفعلٍ فهي فعلية؛ المعنى متقاربٌ والنوع مختلف.', 5)
ON CONFLICT (id) DO UPDATE SET
