  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('237448f3-29d4-5629-885b-505c6ba86757', '9869f61f-81d2-5e18-bd8b-c29d7bf2b4ae', 'أيّ سطرٍ ليس جملةً مفيدةً تامّة؟', '[{"id":"a","text":"يلعبُ الأطفالُ في الساحةِ."},{"id":"b","text":"السماءُ صافيةٌ والجوُّ ..."},{"id":"c","text":"البنتُ مجتهدةٌ."},{"id":"d","text":"نضجَ التمرُ."}]'::jsonb, 'b', '«السماءُ صافيةٌ والجوُّ ...» معناه ناقصٌ ننتظر تمامه، فليست جملةً مفيدةً تامّة، بخلاف البقيّة التي تمّ معناها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

