INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d61b39c-970a-513e-9b9b-7741bc6583bc', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'أيّ سطرٍ جملةٌ فعليةٌ مفيدةٌ ومرتّبة؟', '[{"id":"a","text":"السنونوُّ عشَّهُ يبني فوقَ"},{"id":"b","text":"عشَّ يبني السنونوُّ"},{"id":"c","text":"فوقَ السطحِ السنونوُّ"},{"id":"d","text":"يبني السنونوُّ عشَّهُ فوقَ السطحِ."}]'::jsonb, 'd', '«يبني السنونوُّ عشَّهُ فوقَ السطحِ.» فعليةٌ مرتّبة: فعلٌ «يبني» ثمّ فاعلٌ «السنونوُّ» ثمّ مفعولٌ ومكان، وتنتهي بنقطة، أمّا البقيّة فمبعثرةٌ أو ناقصة.', 1)
