  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('863381db-e354-53ef-a6d7-4ad69a3c4702', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'اقرأ: «تشرقُ الشمسُ صباحًا. الطيورُ تغرّدُ على الأغصانِ.» كم جملةً فعليةً في النصّ؟', '[{"id":"a","text":"لا جملة فعلية"},{"id":"b","text":"جملةٌ فعليةٌ واحدة"},{"id":"c","text":"جملتان فعليتان"},{"id":"d","text":"ثلاث جمل فعلية"}]'::jsonb, 'b', '«تشرقُ الشمسُ صباحًا.» فعليةٌ (بدأت بـ«تشرقُ»)، أمّا «الطيورُ تغرّدُ...» فاسميةٌ لأنّها بدأت بالاسم «الطيورُ» رغم وجود فعلٍ بعده، فالفعلية واحدة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63e23415-4912-513d-bc18-3542ca3327f9', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'ما الكلمة الزائدة التي تُفسد المعنى في: «يقودُ السائقُ الحافلةَ القمرَ.»؟', '[{"id":"a","text":"يقودُ"},{"id":"b","text":"السائقُ"},{"id":"c","text":"القمرَ"},{"id":"d","text":"الحافلةَ"}]'::jsonb, 'c', 'السائق يقودُ الحافلةَ لا القمرَ، فنحذف «القمرَ» لتصير الجملة: «يقودُ السائقُ الحافلةَ.» وتعطي معنًى صحيحًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5d7e210-7386-5802-9b52-3028506613f6', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'حوّل «الفلّاحُ يحصدُ القمحَ.» إلى جملةٍ فعليةٍ مرتّبة:', '[{"id":"a","text":"يحصدُ الفلّاحُ القمحَ."},{"id":"b","text":"القمحَ الفلّاحُ يحصدُ."},{"id":"c","text":"الفلّاحُ القمحَ يحصدُ."},{"id":"d","text":"يحصدُ القمحَ الفلّاحُ."}]'::jsonb, 'a', 'الجملة الفعلية تبدأ بالفعل ثمّ الفاعل ثمّ المفعول: «يحصدُ الفلّاحُ القمحَ.»؛ أمّا «يحصدُ القمحَ الفلّاحُ» فقدّم المفعول على الفاعل والأصل تأخيره.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
