  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4ddc987-f704-5ff1-b4c1-611516f753e2', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'أيّ جملةٍ اسميةٌ صحيحةٌ ومرتّبة؟', '[{"id":"a","text":"واسعٌ الميدانُ."},{"id":"b","text":"الميدانُ واسعُ لاعبون"},{"id":"c","text":"ميدانٌ واسعُ في"},{"id":"d","text":"الميدانُ واسعٌ."}]'::jsonb, 'd', '«الميدانُ واسعٌ.» اسميةٌ مرتّبة: مبتدأٌ «الميدانُ» ثمّ خبرٌ «واسعٌ»؛ أمّا «واسعٌ الميدانُ» فقدّم الخبر، والبقيّة ناقصةٌ أو مبعثرة.', 5)
ON CONFLICT (id) DO UPDATE SET
