INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2399bb3e-26bc-5273-be1f-393b7bf5da72', '6455fceb-26e1-540c-a6ea-e911d76e7512', 'قال طفلٌ: «الجملة الفعلية والاسمية لا فرق بينهما». ما الصحيح؟', '[{"id":"a","text":"صحيح، النوعان سواء"},{"id":"b","text":"خطأ؛ الفعلية تبدأ بفعلٍ والاسمية تبدأ باسمٍ"},{"id":"c","text":"صحيح، كلتاهما تبدأ بفعلٍ"},{"id":"d","text":"خطأ؛ كلتاهما تبدأ باسمٍ"}]'::jsonb, 'b', 'الخطأ الشائع: عدم التمييز. الفرق في أوّل كلمةٍ: الفعلية تبدأ بفعلٍ (يكتبُ، نامَ) والاسمية تبدأ باسمٍ (الشمسُ، البحرُ).', 6)
