INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d900ff9a-b9ab-586b-88ea-e81ae41437df', 'b466515b-6e07-5403-8ef4-d20bb40b48a9', 'أيّ ما يلي جملةٌ مفيدةٌ تامّة؟', '[{"id":"a","text":"إلى المدرسةِ في الصباحِ"},{"id":"b","text":"تلميذُ حقيبةُ كتابُ"},{"id":"c","text":"يذهبُ التلميذُ إلى المدرسةِ."},{"id":"d","text":"ـذهبُ الـ ـة"}]'::jsonb, 'c', '«يذهبُ التلميذُ إلى المدرسةِ.» كلماتٌ مرتّبةٌ تعطي معنًى تامًّا، أمّا البقيّة فمبعثرةٌ أو ناقصةٌ لا يتمّ بها المعنى.', 1)
