INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11979779-90ec-5ab5-8cbb-26978abec313', 'b466515b-6e07-5403-8ef4-d20bb40b48a9', 'في الجملة «يقطفُ الجامعُ الزيتونَ.»، عيّن المفعول به (متمّم المعنى):', '[{"id":"a","text":"يقطفُ"},{"id":"b","text":"الجامعُ"},{"id":"c","text":"لا مفعول فيها"},{"id":"d","text":"الزيتونَ"}]'::jsonb, 'd', '«الزيتونَ» هو ما وقع عليه فعل القطف فهو المفعول به (متمّم المعنى)، و«الجامعُ» فاعلٌ و«يقطفُ» فعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96c38d71-0a3f-565c-b8b2-02b04dc8c016', 'b466515b-6e07-5403-8ef4-d20bb40b48a9', 'أيّ تحويلٍ يجعل «يلعبُ الطفلُ.» جملةً اسمية؟', '[{"id":"a","text":"لعبَ الطفلُ."},{"id":"b","text":"الطفلُ يلعبُ."},{"id":"c","text":"العبْ يا طفلُ."},{"id":"d","text":"يلعبُ طفلٌ صغيرٌ."}]'::jsonb, 'b', 'بتقديم الاسم «الطفلُ» على الفعل تصير الجملة اسمية: «الطفلُ يلعبُ.» (مبتدأٌ ثمّ خبرٌ جملة فعلية)، أمّا البقيّة فتبقى فعلية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('738eca44-5b9a-5fea-9b42-8593965a19ac', 'b466515b-6e07-5403-8ef4-d20bb40b48a9', 'اقرأ: «اخضرَّ الزرعُ. الفلّاحُ سعيدٌ.» صنّف الجملتين بالترتيب:', '[{"id":"a","text":"فعلية ثمّ اسمية"},{"id":"b","text":"اسمية ثمّ فعلية"},{"id":"c","text":"فعليتان"},{"id":"d","text":"اسميتان"}]'::jsonb, 'a', '«اخضرَّ الزرعُ.» بدأت بفعلٍ فهي فعلية، و«الفلّاحُ سعيدٌ.» بدأت باسمٍ فهي اسمية، فالترتيب: فعلية ثمّ اسمية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7b63c71-dd9a-5861-b29c-6be1ebfdbee4', 'b466515b-6e07-5403-8ef4-d20bb40b48a9', 'قال تلميذٌ: «الجملة قد تتمّ بكلمةٍ واحدةٍ فقط». ما الصحيح؟', '[{"id":"a","text":"صحيح، كلمةٌ واحدةٌ تكفي دائمًا"},{"id":"b","text":"صحيح، الفعل وحده جملة"},{"id":"c","text":"خطأ غالبًا؛ الجملة المفيدة تحتاج ركنين يعطيان معنًى تامًّا"},{"id":"d","text":"خطأ؛ الجملة لا تقلّ عن عشر كلمات"}]'::jsonb, 'c', 'الخطأ الشائع: الاكتفاء بكلمةٍ. الجملة المفيدة تقوم على ركنين (مسندٍ ومسندٍ إليه) يعطيان معنًى تامًّا، وليست محصورةً بعددٍ كبيرٍ من الكلمات أيضًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

