INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02f6c1c9-ced9-540d-b569-4c8fd9f9c264', '41053006-aad0-5f89-b5eb-fb81af09d4ff', 'في الجملة الفعلية، الفعل هو:', '[{"id":"a","text":"المسند (الخبر الدالّ على الحدث)"},{"id":"b","text":"المسند إليه"},{"id":"c","text":"المفعول به"},{"id":"d","text":"حرفٌ لا معنى له"}]'::jsonb, 'a', 'الفعل يدلّ على حدثٍ مقترنٍ بزمن، وهو المسند؛ أي الخبر الذي نُسنده إلى صاحبه (الفاعل).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('832d14ea-e7f0-50ed-aabf-3e3dca3b6194', '41053006-aad0-5f89-b5eb-fb81af09d4ff', 'الفاعل في الجملة الفعلية يُسمّى أيضًا:', '[{"id":"a","text":"المفعول به"},{"id":"b","text":"الخبر"},{"id":"c","text":"المسند إليه"},{"id":"d","text":"المسند"}]'::jsonb, 'c', 'الفاعل هو مَن قام بالفعل، وهو المسند إليه؛ أي مَن أُسند إليه الحدث وأُخبر عنه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('616adedc-9b4c-5c8e-9e56-02e1e95d303c', '41053006-aad0-5f89-b5eb-fb81af09d4ff', 'ما علامة رفع الفاعل الأصليّة؟', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"الكسرة"},{"id":"c","text":"السكون"},{"id":"d","text":"الضمّة"}]'::jsonb, 'd', 'الفاعل مرفوعٌ دائمًا، وعلامة رفعه الأصليّة هي الضمّة على آخره، مثل: «نجحَ التلميذُ.»', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44e1cf0d-9060-52cb-bee9-d508acff75e4', '41053006-aad0-5f89-b5eb-fb81af09d4ff', 'في الجملة «ركضَ الحصانُ.»، ما الفاعل (المسند إليه)؟', '[{"id":"a","text":"لا فاعل فيها"},{"id":"b","text":"الحصانُ"},{"id":"c","text":"ركضَ"},{"id":"d","text":"في الميدانِ"}]'::jsonb, 'b', 'نسأل: مَن ركضَ؟ فالجواب «الحصانُ»، فهو الفاعل المسند إليه المرفوع بالضمّة، و«ركضَ» فعلٌ مسند.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
