  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8374724-b293-5939-a98e-46ca99af8a0f', '41053006-aad0-5f89-b5eb-fb81af09d4ff', 'أيّ جملةٍ راعت مطابقة الفعل لفاعله المؤنّث؟', '[{"id":"a","text":"لعبَ البنتُ."},{"id":"b","text":"البنتُ لعبَ."},{"id":"c","text":"لعبتِ البنتُ."},{"id":"d","text":"لعبوا البنتُ."}]'::jsonb, 'c', 'الفاعل «البنتُ» مؤنّثٌ فتلحق الفعلَ تاءُ التأنيث الساكنة: «لعبتِ البنتُ.»؛ أمّا «لعبَ البنتُ» فلم يطابق الفاعل المؤنّث.', 5)
