INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e040949e-f540-5d99-932d-df879e500589', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'في الجملة «لعبَ الولدُ.»، ما الفعل (المسند)؟', '[{"id":"a","text":"الولدُ"},{"id":"b","text":"لعبَ"},{"id":"c","text":"في الساحةِ"},{"id":"d","text":"لا فعل فيها"}]'::jsonb, 'b', '«لعبَ» كلمةٌ تدلّ على حدثٍ وزمنٍ ماضٍ، فهي الفعل (المسند)، و«الولدُ» هو الفاعل الذي قام باللعب.', 1)
