INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0519ebed-bb98-5b9e-acbc-01caddff02a9', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'في الجملة «تطيرُ الفراشةُ.»، مَن الفاعل (المسند إليه)؟', '[{"id":"a","text":"تطيرُ"},{"id":"b","text":"في الحديقةِ"},{"id":"c","text":"الفراشةُ"},{"id":"d","text":"لا فاعل فيها"}]'::jsonb, 'c', 'نسأل: مَن تطيرُ؟ فالجواب «الفراشةُ»، فهي الفاعل (المسند إليه)، و«تطيرُ» فعلٌ يدلّ على الحدث.', 2)
