INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d353616-b5d6-5e97-9fe6-b42dc27ec254', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'ما علامة رفع الفاعل في «نجحَ التلميذُ.»؟', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"السكون"},{"id":"c","text":"الكسرة"},{"id":"d","text":"الضمّة"}]'::jsonb, 'd', 'الفاعل مرفوعٌ دائمًا، وعلامة رفعه الأصليّة الضمّة؛ فـ«التلميذُ» فاعلٌ مرفوعٌ بالضمّة الظاهرة على آخره.', 3)
