INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65e739b8-59b3-5773-a094-6ced2ae96aac', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'بأيّ سؤالٍ نصل إلى الفاعل بعد الفعل؟', '[{"id":"a","text":"مَن فعلَ؟"},{"id":"b","text":"أينَ؟"},{"id":"c","text":"متى؟"},{"id":"d","text":"كيفَ؟"}]'::jsonb, 'a', 'للوصول إلى الفاعل نسأل بعد الفعل «مَن فعلَ؟»؛ فجواب «مَن نجحَ؟» هو الفاعل، أمّا «أينَ» و«متى» فيدلّان على المكان والزمان.', 4)
ON CONFLICT (id) DO UPDATE SET
