INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6b78ba7-6853-5206-94f7-88716f2468ea', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'في الجملة «شربتِ البنتُ الحليبَ.»، عيّن الفاعل:', '[{"id":"a","text":"الحليبَ"},{"id":"b","text":"شربتِ"},{"id":"c","text":"البنتُ"},{"id":"d","text":"لا فاعل فيها"}]'::jsonb, 'c', '«البنتُ» هي مَن قامت بالشرب فهي الفاعل المرفوع بالضمّة، أمّا «الحليبَ» فمفعولٌ به وقع عليه الشرب.', 5)
