INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('761e87ae-4af6-5ba1-bbae-51c74e2bef5a', '63c61abc-f942-51ea-97a6-4a47a1995fd3', 'أيّ جملةٍ طابقَ فيها الفعلُ فاعلَه المؤنّث؟', '[{"id":"a","text":"كتبَ الطالبةُ."},{"id":"b","text":"كتبتِ الطالبةُ."},{"id":"c","text":"كتبوا الطالبةُ."},{"id":"d","text":"الطالبةُ كتبَ."}]'::jsonb, 'b', 'الفاعل «الطالبةُ» مؤنّثٌ فتلحق الفعلَ تاءُ التأنيث الساكنة: «كتبتِ الطالبةُ.»؛ أمّا «كتبَ الطالبةُ» فلم يراعِ المطابقة.', 6)
