INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('474580df-1fca-580d-9fcf-4fe11d2886d3', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'في الجملة «حصدَ الفلّاحُ القمحَ.»، عيّن الفاعل وعلامته:', '[{"id":"a","text":"الفلّاحُ، مرفوعٌ بالضمّة"},{"id":"b","text":"القمحَ، منصوبٌ بالفتحة"},{"id":"c","text":"حصدَ، فعلٌ ماضٍ"},{"id":"d","text":"لا فاعل في الجملة"}]'::jsonb, 'a', 'نسأل: مَن حصدَ؟ «الفلّاحُ»، فهو الفاعل المرفوع بالضمّة، أمّا «القمحَ» فمفعولٌ به منصوبٌ بالفتحة و«حصدَ» فعل.', 1)
