INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a39e047-9f93-5d3a-8b5e-75fac66bacc6', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'أيّ جملةٍ راعت الرتبة الصحيحة (فعلٌ ثمّ فاعل) وهي فعلية؟', '[{"id":"a","text":"العصفورُ غرّدَ."},{"id":"b","text":"غرّدَ العصفورُ فوقَ الغصنِ."},{"id":"c","text":"فوقَ الغصنِ العصفورُ."},{"id":"d","text":"العصفورُ فوقَ الغصنِ."}]'::jsonb, 'b', '«غرّدَ العصفورُ فوقَ الغصنِ.» بدأت بالفعل «غرّدَ» ثمّ الفاعل «العصفورُ» فهي فعليةٌ مرتّبة؛ أمّا «العصفورُ غرّدَ» فبدأت باسمٍ فصارت اسمية.', 2)
