  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aba4308e-d82b-5821-8736-b16376f328da', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'اختر الجملة التي ضبطتِ الفاعلَ المؤنّث ضبطًا سليمًا في الفعل والعلامة:', '[{"id":"a","text":"نجحَ مريمَ في الامتحانِ."},{"id":"b","text":"نجحوا مريمُ في الامتحانِ."},{"id":"c","text":"نجحتْ مريمُ في الامتحانِ."},{"id":"d","text":"نجحَ مريمُ في الامتحانِ."}]'::jsonb, 'c', 'الفاعل «مريمُ» مؤنّثٌ ومرفوعٌ بالضمّة، فيلزم الفعلَ تاءُ التأنيث ويُرفع الاسم: «نجحتْ مريمُ.»؛ أمّا «نجحَ مريمُ» ففاته التأنيث.', 3)
