  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e42ebf4-233e-5646-9727-1c278475c0b9', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'في الجملة «يقرأُ المجتهدونَ الدرسَ.»، ما علامة رفع الفاعل «المجتهدونَ»؟', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"الكسرة"},{"id":"c","text":"السكون"},{"id":"d","text":"الواو، لأنّه جمعُ مذكّرٍ سالم"}]'::jsonb, 'd', '«المجتهدونَ» جمعُ مذكّرٍ سالمٌ، فيُرفع بالواو نيابةً عن الضمّة، وهو فاعلٌ قام بالقراءة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb5c5793-629d-5239-ac7e-008a71b20764', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'حوّل الجملة الاسمية «التلميذُ يكتبُ الدرسَ.» إلى جملةٍ فعليةٍ مرتّبة:', '[{"id":"a","text":"الدرسَ يكتبُ التلميذُ."},{"id":"b","text":"يكتبُ التلميذُ الدرسَ."},{"id":"c","text":"التلميذُ الدرسَ يكتبُ."},{"id":"d","text":"يكتبُ الدرسَ التلميذُ."}]'::jsonb, 'b', 'نقدّم الفعل «يكتبُ» ثمّ الفاعل «التلميذُ» ثمّ المفعول «الدرسَ»: «يكتبُ التلميذُ الدرسَ.»؛ أمّا «يكتبُ الدرسَ التلميذُ» فقدّم المفعول على الفاعل والأصل تأخيره.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06a6e15a-6a12-5e23-abb0-f909aa00d6c8', 'e41cb5d9-acf1-5be4-a09e-e0dea585dce0', 'قال تلميذٌ: «في جملة (أكلَ القطُّ الفأرَ) الفأرُ هو الفاعل». ما الصحيح؟', '[{"id":"a","text":"صحيح، الفأرُ آخرُ الجملةِ فهو الفاعل"},{"id":"b","text":"صحيح، كلاهما فاعل"},{"id":"c","text":"خطأ؛ الفاعل «القطُّ» (مَن أكل، مرفوع)، و«الفأرَ» مفعولٌ به (وقع عليه الأكل، منصوب)"},{"id":"d","text":"خطأ؛ لا فاعل في الجملة أصلًا"}]'::jsonb, 'c', 'الخطأ الشائع: الخلط بين الفاعل والمفعول. الفاعل مَن قام بالفعل «القطُّ» مرفوعٌ بالضمّة، و«الفأرَ» وقع عليه الفعل فهو مفعولٌ به منصوبٌ بالفتحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0a409b21-9b2f-5161-9283-aa635042bb27', '6fe31737-2a36-5ba8-a799-6197824489f2', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الفعل والفاعل', 2, 75, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
