  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a5ab9437-4128-550c-8a91-5971a9852791', '0a409b21-9b2f-5161-9283-aa635042bb27', 'في الجملة «طبخَ الطبّاخُ.»، الفعلُ «طبخَ» يُسمّى في الإسناد:', '[{"id":"a","text":"المسند"},{"id":"b","text":"المسند إليه"},{"id":"c","text":"المفعول به"},{"id":"d","text":"النعت"}]'::jsonb, 'a', 'الفعل في الجملة الفعلية هو المسند؛ أي الخبر الدالّ على الحدث الذي نُسنده إلى الفاعل، والفاعل «الطبّاخُ» هو المسند إليه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('052f81ed-e666-5ea2-9443-54314d19e847', '0a409b21-9b2f-5161-9283-aa635042bb27', 'اقرأ: «صعدَ الجبلَ المتسلّقُ.» ما الخطأ في الرتبة؟', '[{"id":"a","text":"لا خطأ، الجملة سليمة"},{"id":"b","text":"قُدّم المفعول «الجبلَ» على الفاعل «المتسلّقُ»"},{"id":"c","text":"الفعل في غير موضعه"},{"id":"d","text":"الفاعل منصوب"}]'::jsonb, 'b', 'الرتبة الأصليّة: فعلٌ ثمّ فاعلٌ ثمّ مفعول؛ والصواب «صعدَ المتسلّقُ الجبلَ.»، فهنا قُدّم المفعول «الجبلَ» على الفاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f115e654-f62c-5ef5-a492-416886b3ec3a', '0a409b21-9b2f-5161-9283-aa635042bb27', 'أيّ جملةٍ فيها الفاعلُ مرفوعٌ بالضمّة ضبطًا صحيحًا؟', '[{"id":"a","text":"فازَ اللاعبَ."},{"id":"b","text":"فازَ اللاعبِ."},{"id":"c","text":"فازَ اللاعبُ."},{"id":"d","text":"فازَ اللاعبْ."}]'::jsonb, 'c', 'الفاعل «اللاعبُ» مرفوعٌ، وعلامة رفعه الضمّة على آخره: «فازَ اللاعبُ.»؛ أمّا الفتحة والكسرة والسكون فليست علامات رفعٍ هنا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('57c61692-68c4-5d6d-9b9a-77c31f36a1f0', '0a409b21-9b2f-5161-9283-aa635042bb27', 'في الجملة «ذهبتْ سعادُ.»، لماذا لحقت الفعلَ تاءُ التأنيث؟', '[{"id":"a","text":"لأنّ الفاعل «سعادُ» مؤنّث"},{"id":"b","text":"لأنّ الفعل ماضٍ فقط"},{"id":"c","text":"لأنّ الجملة قصيرة"},{"id":"d","text":"لأنّ الفاعل جمعٌ"}]'::jsonb, 'a', 'يطابق الفعلُ فاعلَه في التذكير والتأنيث؛ والفاعل «سعادُ» مؤنّثٌ فلحقت الفعلَ تاءُ التأنيث الساكنة: «ذهبتْ سعادُ.»', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a298cc6b-ec79-5596-81a0-7e513da42003', '0a409b21-9b2f-5161-9283-aa635042bb27', 'عيّن الجملة الفعلية الصحيحة المرتّبة:', '[{"id":"a","text":"الرسالةَ كتبَ خالدٌ."},{"id":"b","text":"خالدٌ كتبَ الرسالةَ."},{"id":"c","text":"كتبَ خالدٌ الرسالةَ."},{"id":"d","text":"كتبَ الرسالةَ خالدٌ."}]'::jsonb, 'c', 'الفعلية المرتّبة: فعلٌ «كتبَ» ثمّ فاعلٌ «خالدٌ» ثمّ مفعولٌ «الرسالةَ»: «كتبَ خالدٌ الرسالةَ.»؛ أمّا «خالدٌ كتبَ...» فاسمية لبدئها باسم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48f4eceb-26e0-5210-a399-2edb7626d1cf', '0a409b21-9b2f-5161-9283-aa635042bb27', 'ما المسند إليه (الفاعل) في «تشرقُ الشمسُ صباحًا.»؟', '[{"id":"a","text":"صباحًا"},{"id":"b","text":"تشرقُ"},{"id":"c","text":"لا فاعل فيها"},{"id":"d","text":"الشمسُ"}]'::jsonb, 'd', 'نسأل: مَن تشرقُ؟ «الشمسُ»، فهي الفاعل (المسند إليه) المرفوع بالضمّة، و«صباحًا» ظرفُ زمانٍ يبيّن وقت الشروق.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

