INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87122a61-034d-53a2-a374-239ba2887219', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'في الجملة «يحرسُ الجنودُ الحدودَ.»، ما إعراب «الجنودُ»؟', '[{"id":"a","text":"فاعلٌ مرفوعٌ، وعلامة رفعه الضمّة"},{"id":"b","text":"مفعولٌ به منصوبٌ بالفتحة"},{"id":"c","text":"فعلٌ مضارع"},{"id":"d","text":"نعتٌ مرفوع"}]'::jsonb, 'a', '«الجنودُ» جمعُ تكسيرٍ وقع فاعلًا، فهو مرفوعٌ وعلامة رفعه الضمّة الظاهرة، و«الحدودَ» مفعولٌ به منصوبٌ بالفتحة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa1ec46b-91c1-53a0-b11f-c5fb694bd82e', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'اقرأ: «وصلَ المسافرونَ. استقبلتْهم العائلةُ.» ما علامة رفع الفاعل «المسافرونَ»؟', '[{"id":"a","text":"الضمّة"},{"id":"b","text":"الواو، لأنّه جمعُ مذكّرٍ سالم"},{"id":"c","text":"الفتحة"},{"id":"d","text":"الكسرة"}]'::jsonb, 'b', '«المسافرونَ» جمعُ مذكّرٍ سالمٌ، فيُرفع بالواو نيابةً عن الضمّة؛ فالواو هنا علامةُ رفعِ الفاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ecbd186-8e2a-587c-8e03-6b4230a8691b', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'أيُّ جملةٍ جمعت الضبط الصحيح: فعلٌ مطابقٌ لفاعلٍ مؤنّثٍ، وفاعلٌ مرفوع، ومفعولٌ منصوب؟', '[{"id":"a","text":"زرعَ الفلّاحةُ الأرضَ."},{"id":"b","text":"زرعتِ الفلّاحةِ الأرضُ."},{"id":"c","text":"زرعتِ الفلّاحةُ الأرضَ."},{"id":"d","text":"زرعتْ الفلّاحةُ الأرضُ."}]'::jsonb, 'c', 'الفاعل «الفلّاحةُ» مؤنّثٌ فتلحق الفعلَ تاءُ التأنيث ويُرفع بالضمّة، و«الأرضَ» مفعولٌ به منصوبٌ بالفتحة: «زرعتِ الفلّاحةُ الأرضَ.»', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83f1b83c-c7ab-5e64-bef6-26fa803c04c1', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'اقرأ: «نظّفتِ البنتُ غرفتَها ثمّ رتّبتْها.» في «رتّبتْها» مَن الفاعل؟', '[{"id":"a","text":"غرفتَها"},{"id":"b","text":"«ـها» الضمير المتّصل"},{"id":"c","text":"ضميرٌ مستترٌ تقديره «هي» يعود على البنتِ"},{"id":"d","text":"لا فاعل في الفعل"}]'::jsonb, 'c', 'الفاعل في «رتّبتْها» ضميرٌ مستترٌ تقديره «هي» يعود على «البنتِ»، و«ـها» ضميرٌ في محلّ نصب مفعولٍ به (الغرفة)؛ فالفاعل ليس ظاهرًا بل مستتر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b86e7492-9a0a-5459-8832-9ed8521a1548', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'ما الجملة الفعلية المرتّبة التي راعت الرتبة وعلامات الإعراب جميعًا؟', '[{"id":"a","text":"القصيدةَ ألقى الشاعرُ."},{"id":"b","text":"ألقى الشاعرُ القصيدةَ."},{"id":"c","text":"الشاعرُ ألقى القصيدةَ."},{"id":"d","text":"ألقى القصيدةَ الشاعرُ."}]'::jsonb, 'b', 'الرتبة: فعلٌ «ألقى» ثمّ فاعلٌ مرفوع «الشاعرُ» ثمّ مفعولٌ منصوب «القصيدةَ»: «ألقى الشاعرُ القصيدةَ.»؛ أمّا «ألقى القصيدةَ الشاعرُ» فقدّم المفعول على الفاعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('020a29b2-cd8b-5dc7-82f1-a49b188a9d86', 'ef709956-480f-5f5a-9d7d-7c2ad70a70f8', 'قال تلميذٌ: «كلّ فعلٍ ماضٍ تلحقه تاءٌ مع الفاعل المؤنّث وجوبًا حتى لو فُصل بينهما». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ مطلقًا في كلّ الحالات"},{"id":"b","text":"خطأ؛ لا تأنيث للفعل أبدًا"},{"id":"c","text":"خطأ؛ الفاعل المؤنّث لا علاقة له بالفعل"},{"id":"d","text":"في مستوانا: مع الفاعل المؤنّث الظاهر تلحق الفعلَ تاءُ التأنيث (نجحتْ مريمُ)"}]'::jsonb, 'd', 'في مستوى السنة الرابعة: متى كان الفاعل مؤنّثًا ظاهرًا لحقت الفعلَ تاءُ التأنيث الساكنة، مثل «نجحتْ مريمُ» و«لعبتِ البنتُ»؛ فالمطابقة في التأنيث قاعدةٌ نلتزمها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

