INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b20a46f1-b770-51ec-8fcc-ea1469c95add', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'في الجملة «هطلَ المطرُ.»، عيّن الفاعل:', '[{"id":"a","text":"المطرُ"},{"id":"b","text":"هطلَ"},{"id":"c","text":"في الشتاءِ"},{"id":"d","text":"لا فاعل فيها"}]'::jsonb, 'a', 'نسأل: ما الذي هطلَ؟ «المطرُ»، فهو الفاعل المرفوع بالضمّة، و«هطلَ» فعلٌ ماضٍ دالٌّ على الحدث.', 1)
