INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1da55dd-1120-5cac-b195-84571caf760f', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'ما الذي يجعل الكلمة فعلًا (مسندًا)؟', '[{"id":"a","text":"دلالتها على ذاتٍ فقط"},{"id":"b","text":"دلالتها على حدثٍ مقترنٍ بزمن"},{"id":"c","text":"كونها في آخر الجملة"},{"id":"d","text":"كونها معرفةً بالـ"}]'::jsonb, 'b', 'الفعل كلمةٌ تدلّ على حدثٍ مقترنٍ بزمن (ماضٍ أو حاضرٍ أو مستقبل) مثل «كتبَ، يكتبُ»، وهو المسند في الجملة الفعلية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bab0d284-490a-5e14-9dbe-01ce89ccbee6', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'أيّ جملةٍ خالفتِ المطابقة بين الفعل وفاعله المؤنّث؟', '[{"id":"a","text":"نامتِ الطفلةُ."},{"id":"b","text":"ذهبتْ فاطمةُ."},{"id":"c","text":"لعبَ البنتُ."},{"id":"d","text":"كتبتِ المعلّمةُ."}]'::jsonb, 'c', '«لعبَ البنتُ» خطأ؛ الفاعل «البنتُ» مؤنّثٌ فيلزم الفعلَ تاءُ التأنيث: «لعبتِ البنتُ.»، والبقيّة راعت المطابقة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d6be2cf-79a8-54f7-8a43-f5153e51cabf', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'في «يكتبُ المعلّمونَ على السبّورةِ.»، ما إعراب «المعلّمونَ»؟', '[{"id":"a","text":"مفعولٌ به منصوب"},{"id":"b","text":"فاعلٌ مرفوعٌ بالفتحة"},{"id":"c","text":"نعتٌ مجرور"},{"id":"d","text":"فاعلٌ مرفوعٌ بالواو (جمعُ مذكّرٍ سالم)"}]'::jsonb, 'd', '«المعلّمونَ» جمعُ مذكّرٍ سالمٌ وقع فاعلًا، فهو مرفوعٌ بالواو نيابةً عن الضمّة، وهو مَن قام بالكتابة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c204db5-9a9c-53b4-a931-882fd70044a3', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'اقرأ: «الفلّاحُ يجمعُ الزيتونَ.» ما الصواب في نوعها وفاعلها؟', '[{"id":"a","text":"فعلية، وفاعلها «الزيتونَ»"},{"id":"b","text":"اسمية، والفاعل في جملة الخبر ضميرٌ مستترٌ تقديره «هو»"},{"id":"c","text":"فعلية، ولا فاعل فيها"},{"id":"d","text":"اسمية، وفاعلها «الفلّاحُ» المنصوب"}]'::jsonb, 'b', 'الجملة بدأت بالاسم «الفلّاحُ» (مبتدأ) فهي اسمية، وخبرها جملة «يجمعُ الزيتونَ» وفاعل «يجمعُ» ضميرٌ مستترٌ تقديره «هو» يعود على الفلّاح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6f3225a-ec68-5615-bac9-c6cde3b54c7f', '6ca2a28b-cf63-5d05-9deb-1d3fae63f5da', 'رتّب لتصنع جملةً فعليةً سليمة من: (القطارَ — ركبَ — المسافرُ):', '[{"id":"a","text":"ركبَ المسافرُ القطارَ."},{"id":"b","text":"القطارَ المسافرُ ركبَ."},{"id":"c","text":"المسافرُ القطارَ ركبَ."},{"id":"d","text":"القطارَ ركبَ المسافرُ."}]'::jsonb, 'a', 'الفعلية المرتّبة: فعلٌ «ركبَ» ثمّ فاعلٌ مرفوع «المسافرُ» ثمّ مفعولٌ منصوب «القطارَ»: «ركبَ المسافرُ القطارَ.»', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

