INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2a2fdec-4ebf-5240-b2a9-13e3f4cf1f23', '8af5088d-df53-5c6c-8641-bbb3e0aecb1a', 'ما المفعول به؟', '[{"id":"a","text":"الاسم الذي يقوم بالفعل"},{"id":"b","text":"الفعل الذي يدلّ على الحدث"},{"id":"c","text":"الاسم الذي وقع عليه فعل الفاعل"},{"id":"d","text":"حرفٌ يربط بين جملتين"}]'::jsonb, 'c', 'المفعول به اسمٌ يدلّ على ما وقع عليه فعل الفاعل، فيُتمّ معنى الجملة الفعلية؛ أمّا الذي يقوم بالفعل فهو الفاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d88a5b5-8b61-5dff-a84a-9425e7725c16', '8af5088d-df53-5c6c-8641-bbb3e0aecb1a', 'ما علامة المفعول به الغالبة؟', '[{"id":"a","text":"الضمّة"},{"id":"b","text":"السكون"},{"id":"c","text":"الكسرة"},{"id":"d","text":"الفتحة"}]'::jsonb, 'd', 'المفعول به منصوبٌ وعلامته الغالبة الفتحة على آخره، بينما الفاعل مرفوعٌ بالضمّة عادةً.', 2)
