  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9367e226-1e37-5d28-bcd7-604a3a8d0d70', '8af5088d-df53-5c6c-8641-bbb3e0aecb1a', 'في الجملة «أكلَ القطُّ السمكةَ.»، ما المفعول به؟', '[{"id":"a","text":"السمكةَ"},{"id":"b","text":"القطُّ"},{"id":"c","text":"أكلَ"},{"id":"d","text":"لا مفعول به فيها"}]'::jsonb, 'a', '«السمكةَ» هي ما وقع عليها الأكل فهي المفعول به (منصوبٌ بالفتحة)، و«القطُّ» فاعلٌ و«أكلَ» فعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6548990-3480-52d6-a895-4c5496524dad', '8af5088d-df53-5c6c-8641-bbb3e0aecb1a', 'أيّ جملةٍ ممّا يلي لا تحتاج مفعولًا به لأنّ فعلها يكتفي بفاعله؟', '[{"id":"a","text":"كتبَ سعيدٌ الدرسَ."},{"id":"b","text":"نامَ الطفلُ مبكّرًا."},{"id":"c","text":"قرأَ الولدُ الكتابَ."},{"id":"d","text":"غرسَ الفلّاحُ الشجرةَ."}]'::jsonb, 'b', '«نامَ» فعلٌ يكتفي بفاعله ولا يقع على شيء، فلا مفعول به في «نامَ الطفلُ مبكّرًا.»، أمّا البقيّة فأفعالها وقعت على مفعولٍ به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6210912-bc15-5faa-888b-1202ab48ad12', '8af5088d-df53-5c6c-8641-bbb3e0aecb1a', 'في الجملة «قرأَهُ التلميذُ.»، ما إعراب الضمير «ـه» المتّصل بالفعل؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"فعلٌ ماضٍ"},{"id":"c","text":"حرفُ جرّ"},{"id":"d","text":"ضميرٌ في محلّ نصب مفعولٍ به"}]'::jsonb, 'd', 'المفعول به يأتي ضميرًا متّصلًا أحيانًا؛ فـ«ـه» في «قرأَهُ» ضميرٌ في محلّ نصب مفعولٍ به (أي قرأ الكتابَ)، والفاعل هو «التلميذُ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

