INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7cc6d522-6e2c-58ff-8464-759b1a4764bb', 'c7f09a33-5a97-5c78-9c89-2585e321bc7c', 'في الجملة «شربَ الطفلُ الحليبَ.»، ما المفعول به؟', '[{"id":"a","text":"الطفلُ"},{"id":"b","text":"الحليبَ"},{"id":"c","text":"شربَ"},{"id":"d","text":"لا مفعول به فيها"}]'::jsonb, 'b', '«الحليبَ» هو ما وقع عليه فعل الشرب فهو المفعول به، و«الطفلُ» فاعلٌ (مَن شرب) و«شربَ» فعل.', 1)
