INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d391f59-3054-545a-b9ee-9386c816ef5c', 'c7f09a33-5a97-5c78-9c89-2585e321bc7c', 'المفعول به اسمٌ يدلّ على:', '[{"id":"a","text":"مَن قام بالفعل"},{"id":"b","text":"زمن وقوع الفعل"},{"id":"c","text":"ما وقع عليه فعل الفاعل"},{"id":"d","text":"مكان وقوع الفعل"}]'::jsonb, 'c', 'المفعول به اسمٌ يدلّ على ما وقع عليه فعل الفاعل، فيُتمّ معنى الجملة الفعلية؛ أمّا مَن قام بالفعل فهو الفاعل.', 3)
