INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddc0d52b-ec76-59e7-9c12-4f803b4273f6', 'c7f09a33-5a97-5c78-9c89-2585e321bc7c', 'في الجملة «فتحَ سميرٌ البابَ.»، عيّن المفعول به:', '[{"id":"a","text":"سميرٌ"},{"id":"b","text":"فتحَ"},{"id":"c","text":"البابَ"},{"id":"d","text":"لا مفعول به فيها"}]'::jsonb, 'c', '«البابَ» هو ما وقع عليه فعل الفتح فهو المفعول به المنصوب بالفتحة، و«سميرٌ» فاعلٌ قام بالفتح.', 4)
