INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f9b605f-9163-524f-a5a9-41b0f48d32f9', 'c7f09a33-5a97-5c78-9c89-2585e321bc7c', 'للوصول إلى المفعول به نسأل:', '[{"id":"a","text":"على مَن وقع الفعل؟ (أو: ماذا فعل الفاعل؟)"},{"id":"b","text":"مَن فعلَ؟"},{"id":"c","text":"متى وقع الفعل؟"},{"id":"d","text":"أينَ وقع الفعل؟"}]'::jsonb, 'a', 'نصل إلى المفعول به بسؤال «على مَن (أو ماذا) وقع الفعل؟»؛ أمّا «مَن فعلَ؟» فجوابه الفاعل، و«متى/أين» للزمان والمكان.', 5)
