INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('878efac8-fb3c-50a6-8d64-7394f380ed51', '0d777890-4dd4-5a94-ae31-7d768faba3b8', 'في الجملة «ساعدَتْها أمُّها.»، ما إعراب الضمير «ـها» المتّصل بالفعل؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"حرفُ جرّ"},{"id":"c","text":"ضميرٌ في محلّ نصب مفعولٍ به"},{"id":"d","text":"نعتٌ منصوب"}]'::jsonb, 'c', 'يأتي المفعول به ضميرًا متّصلًا؛ فـ«ـها» في «ساعدَتْها» ضميرٌ في محلّ نصب مفعولٍ به، والفاعل «أمُّها» مرفوعٌ بالضمّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0835e86a-ecb0-59f4-ae46-4b2407ce4e91', '0d777890-4dd4-5a94-ae31-7d768faba3b8', 'أيّ جملةٍ فعلها يكتفي بفاعله فلا مفعولَ به فيها؟', '[{"id":"a","text":"كتبَ الولدُ الواجبَ."},{"id":"b","text":"جلسَ الضيفُ على الكرسيِّ."},{"id":"c","text":"قطفَ سعيدٌ الوردةَ."},{"id":"d","text":"أكلَ القطُّ السمكةَ."}]'::jsonb, 'b', '«جلسَ» فعلٌ يكتفي بفاعله ولا يقع على مفعول، فلا مفعول به في «جلسَ الضيفُ على الكرسيِّ.» («على الكرسيِّ» جارٌّ ومجرورٌ لا مفعول)، أمّا البقيّة فلها مفعولٌ به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a56300f4-97b7-58c1-8a04-130d9826cea9', '0d777890-4dd4-5a94-ae31-7d768faba3b8', 'رتّب لتصنع جملةً فعليةً سليمة من: (الرسالةَ — كتبَ — خالدٌ):', '[{"id":"a","text":"كتبَ خالدٌ الرسالةَ."},{"id":"b","text":"الرسالةَ خالدٌ كتبَ."},{"id":"c","text":"خالدٌ الرسالةَ كتبَ."},{"id":"d","text":"الرسالةَ كتبَ خالدٌ."}]'::jsonb, 'a', 'الرتبة الأصليّة: فعلٌ «كتبَ» ثمّ فاعلٌ مرفوع «خالدٌ» ثمّ مفعولٌ منصوب «الرسالةَ»: «كتبَ خالدٌ الرسالةَ.»', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de1bf127-a5da-5d93-bc11-8dd04187bf63', '0d777890-4dd4-5a94-ae31-7d768faba3b8', 'قال تلميذٌ: «كلّ جملةٍ فعليةٍ لا بدّ أن يكون فيها مفعولٌ به». ما الصحيح؟', '[{"id":"a","text":"صحيح، لا تتمّ الجملة الفعلية بلا مفعول"},{"id":"b","text":"صحيح، الفاعل هو المفعول نفسه"},{"id":"c","text":"صحيح، كلّ فعلٍ يقع على شيء"},{"id":"d","text":"خطأ؛ بعض الأفعال تكتفي بفاعلها مثل «نامَ» و«جلسَ»"}]'::jsonb, 'd', 'الخطأ الشائع: ظنّ أنّ كلّ فعلٍ يحتاج مفعولًا. بعض الأفعال تكتفي بفاعلها ولا يقع فعلها على شيء، مثل «نامَ الطفلُ» و«جلسَ الضيفُ»، فلا مفعول به فيها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

