  ('2c29762b-c175-5b62-986a-7f854f9f13a2', 'ecf6e2d7-2ca3-5155-b67b-052d032180d4', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): المفعول به', 2, 75, 15, 'practice', 'admin', 3)
