INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('706101a4-92b3-5b45-babd-eb2fb04b4a7e', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'في الجملة «كتبَ خالدٌ الرسالةَ.»، رتّب الأركان الثلاثة:', '[{"id":"a","text":"مفعولٌ به ← فاعل ← فعل"},{"id":"b","text":"فعل ← فاعل ← مفعولٌ به"},{"id":"c","text":"فاعل ← فعل ← مفعولٌ به"},{"id":"d","text":"فعل ← مفعولٌ به ← فاعل"}]'::jsonb, 'b', 'الرتبة الأصليّة في الجملة الفعلية: فعلٌ «كتبَ» ثمّ فاعلٌ «خالدٌ» ثمّ مفعولٌ به «الرسالةَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55894cfc-f1ad-51f9-90b2-b9ea324a12dc', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'أيّ كلمةٍ في «حلبَ الراعي الناقةَ.» وقع عليها الفعل؟', '[{"id":"a","text":"الراعي"},{"id":"b","text":"حلبَ"},{"id":"c","text":"الناقةَ"},{"id":"d","text":"لا شيء وقع عليه الفعل"}]'::jsonb, 'c', '«الناقةَ» وقع عليها فعل الحلب فهي المفعول به المنصوب، و«الراعي» فاعلٌ قام بالحلب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49846513-f855-5538-933a-e85f00c19eb4', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'في الجملة «زارَنا الجدُّ.»، ما إعراب الضمير «ـنا»؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"حرفٌ زائد"},{"id":"c","text":"اسمٌ مجرور"},{"id":"d","text":"ضميرٌ في محلّ نصب مفعولٍ به"}]'::jsonb, 'd', '«ـنا» في «زارَنا» ضميرٌ متّصلٌ في محلّ نصب مفعولٍ به (أي زارَ نا)، والفاعل «الجدُّ» مرفوعٌ بالضمّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c6ef2ef-cf6e-5bff-8145-4932c2ae19d1', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'أكمل بمفعولٍ به مناسبٍ منصوب: «دقَّ النّجّارُ ___.»', '[{"id":"a","text":"المسمارَ"},{"id":"b","text":"بسرعةٍ"},{"id":"c","text":"في الورشةِ"},{"id":"d","text":"المسمارُ"}]'::jsonb, 'a', 'نحتاج اسمًا وقع عليه الدقّ منصوبًا بالفتحة: «دقَّ النّجّارُ المسمارَ.»؛ أمّا «المسمارُ» فمرفوعٌ لا يصلح مفعولًا، و«بسرعةٍ/في الورشةِ» ليسا مفعولًا به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6558af9-89a8-5cdc-a4f6-7734ee19ed4a', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'أيّ جملةٍ لا مفعولَ به فيها؟', '[{"id":"a","text":"ابتلعَ الحوتُ السمكةَ."},{"id":"b","text":"ركضَ العدّاءُ بسرعةٍ."},{"id":"c","text":"حملَ العاملُ الصندوقَ."},{"id":"d","text":"قرأَ التلميذُ الكتابَ."}]'::jsonb, 'b', '«ركضَ» فعلٌ يكتفي بفاعله، فلا مفعول به في «ركضَ العدّاءُ بسرعةٍ.» («بسرعةٍ» بيانٌ للكيفية لا مفعول)، أمّا البقيّة ففيها مفعولٌ به منصوب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('662c5a0d-e6bc-58ce-a650-0bf009343abe', '2c29762b-c175-5b62-986a-7f854f9f13a2', 'ميّز الفاعل من المفعول به في «طاردَ القطُّ الفأرَ.»:', '[{"id":"a","text":"الفأرُ فاعلٌ، والقطُّ مفعولٌ به"},{"id":"b","text":"لا فاعل ولا مفعول فيها"},{"id":"c","text":"القطُّ فاعلٌ (مَن طارد)، والفأرَ مفعولٌ به (وقعت عليه المطاردة)"},{"id":"d","text":"كلاهما فاعل"}]'::jsonb, 'c', 'نسأل: مَن طارد؟ «القطُّ» فاعلٌ مرفوع. وعلى مَن وقعت المطاردة؟ «الفأرَ» مفعولٌ به منصوب؛ فلا نخلط بينهما لمجرّد الترتيب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

