  ('0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'ecf6e2d7-2ca3-5155-b67b-052d032180d4', 'arabic-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد المتمّمات', 4, 300, 60, 'challenge', 'admin', 4)
