INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d3620f9-8f9a-5863-aef1-592141a40a1a', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'في الجملة «منحَ المعلّمُ التلميذَ جائزةً.»، ما المفعول به الأوّل؟', '[{"id":"a","text":"التلميذَ"},{"id":"b","text":"المعلّمُ"},{"id":"c","text":"جائزةً"},{"id":"d","text":"منحَ"}]'::jsonb, 'a', 'بعض الأفعال تنصب مفعولين؛ ففي «منحَ المعلّمُ التلميذَ جائزةً» المفعول الأوّل «التلميذَ» والثاني «جائزةً»، وكلاهما منصوبٌ بالفتحة، و«المعلّمُ» فاعلٌ مرفوع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
