  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5048f22d-82d1-511d-be2e-b0327930bd27', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'اقرأ: «اشترى الأبُ هديّةً ثمّ غلّفَها.» في «غلّفَها»، ما إعراب «ـها»؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"ضميرٌ في محلّ نصب مفعولٍ به يعود على الهديّةِ"},{"id":"c","text":"حرفُ جرّ"},{"id":"d","text":"ظرفُ مكان"}]'::jsonb, 'b', '«ـها» في «غلّفَها» ضميرٌ متّصلٌ في محلّ نصب مفعولٍ به يعود على «الهديّةِ»، والفاعل ضميرٌ مستترٌ تقديره «هو» يعود على الأب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
