  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbb13078-f331-56ba-ab27-f3cde6bf300f', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'أيُّ جملةٍ جمعت الضبط السليم: فاعلٌ مرفوعٌ ومفعولٌ به منصوب؟', '[{"id":"a","text":"كسرَ الطفلُ الكأسِ."},{"id":"b","text":"كسرَ الطفلَ الكأسَ."},{"id":"c","text":"كسرَ الطفلُ الكأسَ."},{"id":"d","text":"كسرَ الطفلِ الكأسُ."}]'::jsonb, 'c', 'الفاعل «الطفلُ» مرفوعٌ بالضمّة، والمفعول به «الكأسَ» منصوبٌ بالفتحة: «كسرَ الطفلُ الكأسَ.»؛ أمّا البقيّة فخلطت بين علامتي الرفع والنصب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('356ba54a-a302-58f8-b8ad-180dfe93a9e5', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'في الجملة «أعطيتُكَ الكتابَ.»، عيّن مفعولَيِ الفعل:', '[{"id":"a","text":"لا مفعول في الجملة"},{"id":"b","text":"الكتابَ فقط"},{"id":"c","text":"التاء فقط (تاء الفاعل)"},{"id":"d","text":"«ـكَ» (مفعولٌ أوّل) و«الكتابَ» (مفعولٌ ثانٍ)"}]'::jsonb, 'd', 'التاء في «أعطيتُ» فاعلٌ، و«ـكَ» ضميرٌ في محلّ نصب مفعولٍ أوّل، و«الكتابَ» مفعولٌ ثانٍ منصوب؛ ففعل «أعطى» ينصب مفعولين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa63b1d7-e537-58c6-a428-61ccaf7a11a9', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'اقرأ: «قطفَ البستانيُّ الوردةَ الحمراءَ.» ما المفعول به، وما «الحمراءَ»؟', '[{"id":"a","text":"المفعول به «الوردةَ»، و«الحمراءَ» نعتٌ تابعٌ له منصوب"},{"id":"b","text":"المفعول به «الحمراءَ» فقط"},{"id":"c","text":"المفعول به «البستانيُّ»"},{"id":"d","text":"لا مفعول به في الجملة"}]'::jsonb, 'a', '«الوردةَ» مفعولٌ به منصوبٌ بالفتحة، و«الحمراءَ» نعتٌ يتبعه في النصب؛ فالنعت يطابق منعوته في الحركة، و«البستانيُّ» فاعلٌ مرفوع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73392df5-fc58-5ebc-810b-c0153973ec68', '0173d4dd-e19a-5f06-9309-b1baa5ece44e', 'قال تلميذٌ: «الكلمة المنصوبة في آخر الجملة الفعلية تكون دائمًا مفعولًا به». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ دائمًا بلا استثناء"},{"id":"b","text":"خطأ؛ قد تكون منصوبًا آخر (كحالٍ أو ظرفٍ)، فلا يُحكَم بالنصب وحده بل بالمعنى"},{"id":"c","text":"صحيح، كلّ منصوبٍ مفعولٌ به"},{"id":"d","text":"خطأ؛ المفعول به مرفوعٌ لا منصوب"}]'::jsonb, 'b', 'الخطأ الشائع: الحكم بالموقع والحركة وحدهما. ليس كلّ منصوبٍ مفعولًا به؛ فقد يكون ظرفًا («مساءً») أو حالًا، والعبرة بالمعنى: مَن وقع عليه الفعل هو المفعول به.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

