INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47ab598c-9e42-51ad-8098-0f515053fe8a', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'في الجملة «حصدَ الفلّاحُ القمحَ.»، عيّن المفعول به:', '[{"id":"a","text":"الفلّاحُ"},{"id":"b","text":"القمحَ"},{"id":"c","text":"حصدَ"},{"id":"d","text":"لا مفعول به فيها"}]'::jsonb, 'b', '«القمحَ» هو ما وقع عليه فعل الحصاد فهو المفعول به المنصوب بالفتحة، و«الفلّاحُ» فاعلٌ مرفوع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54f23aa1-ab97-5481-bfa9-bc209d2730af', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'علامة نصب المفعول به الغالبة هي:', '[{"id":"a","text":"الكسرة"},{"id":"b","text":"الضمّة"},{"id":"c","text":"السكون"},{"id":"d","text":"الفتحة"}]'::jsonb, 'd', 'المفعول به منصوبٌ وعلامته الغالبة الفتحة على آخره، وبها يُفرَّق عن الفاعل المرفوع بالضمّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1910790-8591-5d27-bbb9-d366ef37ae68', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'أيّ جملةٍ يكتفي فعلها بفاعله (لا مفعول به)؟', '[{"id":"a","text":"نامَ الرضيعُ في المهدِ."},{"id":"b","text":"كتبَ التلميذُ الدرسَ."},{"id":"c","text":"شربَ العصفورُ الماءَ."},{"id":"d","text":"حملَ الرجلُ الحقيبةَ."}]'::jsonb, 'a', '«نامَ» فعلٌ يكتفي بفاعله ولا يقع على مفعول، فلا مفعول به في «نامَ الرضيعُ في المهدِ.» («في المهدِ» جارٌّ ومجرور)، أمّا البقيّة ففيها مفعولٌ به.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ffda57c-d43f-52d8-be1d-f5283ba968b5', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'في الجملة «كافأَتْهُ المعلّمةُ.»، ما إعراب «ـه»؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"ضميرٌ في محلّ نصب مفعولٍ به"},{"id":"c","text":"حرفُ جرّ"},{"id":"d","text":"نعتٌ منصوب"}]'::jsonb, 'b', '«ـه» في «كافأَتْهُ» ضميرٌ متّصلٌ في محلّ نصب مفعولٍ به، والفاعل «المعلّمةُ» مرفوعٌ بالضمّة، والتاء للتأنيث.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ebfcc7bf-ef81-5b6c-991e-db284547f061', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'أكمل بمفعولٍ به مناسبٍ منصوب: «ركبَ الفارسُ ___.»', '[{"id":"a","text":"بسرعةٍ"},{"id":"b","text":"في الميدانِ"},{"id":"c","text":"الحصانُ"},{"id":"d","text":"الحصانَ"}]'::jsonb, 'd', 'نحتاج اسمًا وقع عليه الركوب منصوبًا بالفتحة: «ركبَ الفارسُ الحصانَ.»؛ أمّا «الحصانُ» فمرفوعٌ لا يصلح مفعولًا، و«بسرعةٍ/في الميدانِ» ليسا مفعولًا به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a67d5a1-649a-5744-a6da-a7061d816058', 'ca3fe040-c48d-5423-b90a-bb184de608fe', 'اقرأ: «رسمَ سعيدٌ منظرًا جميلًا.» ما المفعول به وما «جميلًا»؟', '[{"id":"a","text":"المفعول به «سعيدٌ»"},{"id":"b","text":"لا مفعول به في الجملة"},{"id":"c","text":"المفعول به «منظرًا»، و«جميلًا» نعتٌ تابعٌ له منصوب"},{"id":"d","text":"المفعول به «جميلًا» فقط"}]'::jsonb, 'c', '«منظرًا» مفعولٌ به منصوبٌ بالفتحة (ما وقع عليه الرسم)، و«جميلًا» نعتٌ يتبعه في النصب، و«سعيدٌ» فاعلٌ مرفوع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('559da091-e772-56a6-8216-2fbd1c46c96a', 'c950ba90-d48f-55e1-bfbb-167854dfe935', 'arabic-4eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
