INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78a3c7a0-4646-54a0-a59b-792e9455c6a1', '559da091-e772-56a6-8216-2fbd1c46c96a', 'ما النعت (الصفة)؟', '[{"id":"a","text":"اسمٌ نبدأ به الجملة"},{"id":"b","text":"كلمةٌ تصف اسمًا قبلها وتبيّن صفةً من صفاته"},{"id":"c","text":"فعلٌ يدلّ على حدثٍ وزمن"},{"id":"d","text":"حرفٌ يربط بين كلمتين"}]'::jsonb, 'b', 'النعت كلمةٌ تصف اسمًا قبلها (المنعوت) وتبيّن صفةً من صفاته، مثل «مجتهدٌ» في «ولدٌ مجتهدٌ»؛ وهو ليس فعلًا ولا حرفًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e37b915-9e0e-510c-a692-3a8144e20f60', '559da091-e772-56a6-8216-2fbd1c46c96a', 'في الجملة «قرأتُ كتابًا مفيدًا»، ما المنعوت (الموصوف)؟', '[{"id":"a","text":"قرأتُ"},{"id":"b","text":"مفيدًا"},{"id":"c","text":"كتابًا"},{"id":"d","text":"لا منعوت في الجملة"}]'::jsonb, 'c', 'المنعوت هو الاسم الموصوف، وهو «كتابًا»؛ أمّا «مفيدًا» فهو النعت الذي يصفه ويبيّن صفته.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91f5a4cb-abf2-535c-b813-a6a00e27c895', '559da091-e772-56a6-8216-2fbd1c46c96a', 'أيُّ تركيبٍ صحيحٌ في المطابقة؟', '[{"id":"a","text":"بنتٌ مجتهدٌ"},{"id":"b","text":"الوردةُ الجميلُ"},{"id":"c","text":"وردةٌ جميلٌ"},{"id":"d","text":"بنتٌ مجتهدةٌ"}]'::jsonb, 'd', '«بنتٌ» مؤنّثةٌ فلا بدّ أن يكون نعتها مؤنّثًا «مجتهدةٌ»؛ أمّا «بنتٌ مجتهدٌ» و«الوردةُ الجميلُ» و«وردةٌ جميلٌ» ففيها وصفُ مؤنّثٍ بصفةٍ مذكّرةٍ وهو خطأ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ced38d00-e850-529f-bd10-093c70396349', '559da091-e772-56a6-8216-2fbd1c46c96a', 'كيف نصف «الولدُ» (معرفة) بالنعت «مجتهد»؟', '[{"id":"a","text":"الولدُ المجتهدُ"},{"id":"b","text":"الولدُ مجتهدٌ"},{"id":"c","text":"ولدٌ المجتهدُ"},{"id":"d","text":"الولدُ مجتهدةٌ"}]'::jsonb, 'a', 'المنعوت «الولدُ» معرفةٌ (فيه الـ)، فيجب أن يكون النعت معرفةً مثله «المجتهدُ»؛ فنقول «الولدُ المجتهدُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97bfef87-027b-54a9-bdd2-3cd957832a4b', '559da091-e772-56a6-8216-2fbd1c46c96a', 'ما الصواب في وصف جمع الأشياء «كتب»؟', '[{"id":"a","text":"كتبٌ مفيدٌ"},{"id":"b","text":"كتبٌ مفيدةٌ"},{"id":"c","text":"كتبٌ مفيدون"},{"id":"d","text":"كتابٌ مفيدةٌ"}]'::jsonb, 'b', 'جمعُ غير العاقل (الأشياء) مثل «كتب» يُوصف بصفةٍ مفردةٍ مؤنّثةٍ، فنقول «كتبٌ مفيدةٌ»؛ ولا نقول «مفيدٌ» ولا «مفيدون».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

