INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91e85558-a90f-5d16-8c36-f23474ffdb4d', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'في «ولدٌ مجتهدٌ»، ما النعت (الصفة)؟', '[{"id":"a","text":"ولدٌ"},{"id":"b","text":"مجتهدٌ"},{"id":"c","text":"لا نعت فيها"},{"id":"d","text":"كلاهما منعوت"}]'::jsonb, 'b', '«مجتهدٌ» كلمةٌ تصف الاسم «ولدٌ» وتبيّن صفته فهي النعت، و«ولدٌ» هو المنعوت (الموصوف).', 1)
