INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('677fee36-dd6e-5a15-98b1-758764c08c33', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'أكمل: «بنتٌ ___» (بنعتٍ مطابقٍ صحيح):', '[{"id":"a","text":"مجتهدٌ"},{"id":"b","text":"مجتهدةٌ"},{"id":"c","text":"مجتهدون"},{"id":"d","text":"يجتهدُ"}]'::jsonb, 'b', '«بنتٌ» مؤنّثةٌ فيكون نعتها مؤنّثًا «مجتهدةٌ»؛ أمّا «مجتهدٌ» فمذكّرٌ لا يطابق، و«يجتهدُ» فعلٌ لا نعت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba870be9-dcc4-5169-bb58-fefda31f6038', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'النعت يجيب عن السؤال:', '[{"id":"a","text":"متى؟"},{"id":"b","text":"أينَ؟"},{"id":"c","text":"مَن فعلَ؟"},{"id":"d","text":"كيف هو المنعوت؟ (ما صفته؟)"}]'::jsonb, 'd', 'النعت يبيّن صفةَ المنعوت فيجيب عن «كيف هو؟»؛ فنقول الوردةُ… كيف هي؟ «حمراءُ»، أمّا «متى/أين» فللزمان والمكان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40e8647c-a713-52a4-bde8-0fab0f6b3624', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'أيّ تركيبٍ راعى المطابقة في التعريف؟', '[{"id":"a","text":"ولدٌ المجتهدُ"},{"id":"b","text":"الولدُ مجتهدٌ"},{"id":"c","text":"الولدُ المجتهدُ"},{"id":"d","text":"ولدُ مجتهدةٌ"}]'::jsonb, 'c', 'المنعوت «الولدُ» معرفةٌ (فيه الـ) فيكون النعت معرفةً مثله «المجتهدُ»: «الولدُ المجتهدُ.»؛ فلا نخلط معرفةً بنكرة.', 4)
