  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30f2764d-72b9-5a09-a18c-e3d6c6f66cc9', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'ما الصواب في وصف «حديقة» (مؤنّث)؟', '[{"id":"a","text":"حديقةٌ واسعةٌ"},{"id":"b","text":"حديقةٌ واسعٌ"},{"id":"c","text":"حديقةٌ واسعون"},{"id":"d","text":"حديقةُ يتّسعُ"}]'::jsonb, 'a', '«حديقةٌ» مؤنّثةٌ فيكون نعتها مؤنّثًا «واسعةٌ»: «حديقةٌ واسعةٌ.»؛ أمّا «واسعٌ» فمذكّرٌ لا يطابق المؤنّث.', 5)
