INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46cf68e7-b0b7-5eae-99bd-d1c6e6435b8e', 'f03c7bd3-6e25-5537-a0f7-48d5030b79c8', 'في «رأيتُ القمرَ المنيرَ»، النعت «المنيرَ» جاء منصوبًا لأنّه:', '[{"id":"a","text":"تبع منعوته «القمرَ» المنصوب في الحركة"},{"id":"b","text":"نعتٌ يُنصب دائمًا"},{"id":"c","text":"فاعلٌ منصوب"},{"id":"d","text":"مبتدأٌ منصوب"}]'::jsonb, 'a', 'النعت يتبع منعوته في الحركة (الإعراب)؛ فلمّا كان «القمرَ» منصوبًا (مفعولًا به) تبعه النعت «المنيرَ» في النصب.', 6)
ON CONFLICT (id) DO UPDATE SET
