INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('175f60d7-c3ee-59cf-9850-9654bdbe85c5', 'd6387948-1806-57de-be86-360df32b501d', 'في الجملة «جاءَ الرجلُ الطويلُ.»، عيّن النعت والمنعوت:', '[{"id":"a","text":"المنعوت «الرجلُ» والنعت «الطويلُ»"},{"id":"b","text":"المنعوت «الطويلُ» والنعت «الرجلُ»"},{"id":"c","text":"المنعوت «جاءَ»"},{"id":"d","text":"لا نعت في الجملة"}]'::jsonb, 'a', '«الرجلُ» هو الاسم الموصوف (المنعوت)، و«الطويلُ» يصفه ويبيّن صفته فهو النعت، وقد تبعه في الرفع والتعريف.', 1)
