INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64804b24-8b22-54b6-8ef7-18007c181c0c', 'd6387948-1806-57de-be86-360df32b501d', 'أيّ تركيبٍ صحيحٌ في وصف جمع الأشياء «أزهار»؟', '[{"id":"a","text":"أزهارٌ جميلٌ"},{"id":"b","text":"أزهارٌ جميلةٌ"},{"id":"c","text":"أزهارٌ جميلون"},{"id":"d","text":"زهرةٌ جميلون"}]'::jsonb, 'b', 'جمعُ غير العاقل (الأشياء) مثل «أزهار» يُوصف بصفةٍ مفردةٍ مؤنّثةٍ: «أزهارٌ جميلةٌ.»؛ فلا نقول «جميلٌ» ولا «جميلون».', 2)
ON CONFLICT (id) DO UPDATE SET
