  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34bbea45-0ffe-542e-994b-aa2729736834', 'd6387948-1806-57de-be86-360df32b501d', 'صحّح الخطأ في «الطالباتُ المجتهدُ»:', '[{"id":"a","text":"الطالباتُ المجتهدونَ"},{"id":"b","text":"الطالباتُ مجتهدٌ"},{"id":"c","text":"الطالباتُ المجتهداتُ"},{"id":"d","text":"الطالبُ المجتهدُ"}]'::jsonb, 'c', 'المنعوت «الطالباتُ» جمعُ مؤنّثٍ معرفة، فيكون النعت جمعَ مؤنّثٍ معرفةً مطابقًا: «الطالباتُ المجتهداتُ.»؛ أمّا «المجتهدونَ» فجمع مذكّر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b0cd157-6bcd-5468-982c-2d1f4249c21a', 'd6387948-1806-57de-be86-360df32b501d', 'في «اشتريتُ كتابًا مفيدًا»، لماذا جاء النعت «مفيدًا» منوّنًا منصوبًا؟', '[{"id":"a","text":"لأنّ النعت يُنصب دائمًا"},{"id":"b","text":"لأنّه فاعلٌ منصوب"},{"id":"c","text":"بلا سببٍ، هكذا يُنطق"},{"id":"d","text":"تبع منعوته «كتابًا» النكرةَ المنصوبَ في التنكير والحركة"}]'::jsonb, 'd', 'النعت يطابق منعوته في التنكير والحركة؛ و«كتابًا» نكرةٌ منصوبةٌ (مفعولٌ به) فتبعه «مفيدًا» نكرةً منصوبةً منوّنةً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbad1a5c-7f01-5e2a-9f6a-50686f7d89fe', 'd6387948-1806-57de-be86-360df32b501d', 'أيّ جملةٍ طابقَ فيها النعتُ منعوتَه في الأمور الأربعة جميعًا؟', '[{"id":"a","text":"اللاعبونَ الماهرُ فازوا."},{"id":"b","text":"اللاعبونَ الماهرونَ فازوا."},{"id":"c","text":"اللاعبونَ ماهراتٌ فازوا."},{"id":"d","text":"اللاعبُ الماهرونَ فازوا."}]'::jsonb, 'b', 'المنعوت «اللاعبونَ» جمعُ مذكّرٍ معرفةٍ مرفوع، فيطابقه النعت في التذكير والجمع والتعريف والرفع: «اللاعبونَ الماهرونَ.»', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b27ddaa-20c5-51e1-a5c8-686273a9552c', 'd6387948-1806-57de-be86-360df32b501d', 'قال تلميذٌ: «النعت يطابق منعوته في التذكير والتأنيث فقط». ما الصحيح؟', '[{"id":"a","text":"خطأ؛ يطابقه أيضًا في الإفراد والجمع، والتعريف والتنكير، والحركة (الإعراب)"},{"id":"b","text":"صحيح، لا مطابقة إلّا في التذكير والتأنيث"},{"id":"c","text":"صحيح، الحركة لا تتبع المنعوت"},{"id":"d","text":"خطأ؛ لا مطابقة بين النعت ومنعوته أصلًا"}]'::jsonb, 'a', 'الخطأ الشائع: حصر المطابقة في التذكير والتأنيث. النعت يتبع منعوته في أربعةٍ: التذكير/التأنيث، والإفراد/الجمع، والتعريف/التنكير، والحركة (الإعراب).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

