  ('52362a34-1225-5057-ac82-568e14f89c91', 'c950ba90-d48f-55e1-bfbb-167854dfe935', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): النعت والتطابق', 2, 75, 15, 'practice', 'admin', 3)
