INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0267d3ac-3968-5913-83f2-6370ccb7eba9', '52362a34-1225-5057-ac82-568e14f89c91', 'كم أمرًا يطابق فيها النعتُ منعوتَه؟', '[{"id":"a","text":"أربعة"},{"id":"b","text":"اثنان"},{"id":"c","text":"واحد"},{"id":"d","text":"لا مطابقة"}]'::jsonb, 'a', 'النعت يتبع منعوته في أربعة أمورٍ: التذكير/التأنيث، والإفراد/الجمع، والتعريف/التنكير، والحركة (الإعراب).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
