  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e6224fd-abda-565b-b098-c6ecc39bd599', '52362a34-1225-5057-ac82-568e14f89c91', 'أيّ تركيبٍ فيه خطأٌ في المطابقة؟', '[{"id":"a","text":"بحرٌ واسعٌ"},{"id":"b","text":"سيّارةٌ سريعٌ"},{"id":"c","text":"قمرٌ منيرٌ"},{"id":"d","text":"بنتٌ مؤدّبةٌ"}]'::jsonb, 'b', '«سيّارةٌ» مؤنّثةٌ فيجب وصفها بمؤنّثٍ «سريعةٌ»؛ فـ«سيّارةٌ سريعٌ» خطأٌ لوصف المؤنّث بمذكّر، والبقيّة سليمةُ المطابقة.', 3)
ON CONFLICT (id) DO UPDATE SET
