  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0ee236b-d11a-5d76-95a3-d0e66326f2dc', '52362a34-1225-5057-ac82-568e14f89c91', 'ما الصواب في وصف «أقلام» (جمعُ أشياء)؟', '[{"id":"a","text":"أقلامٌ ملوّنون"},{"id":"b","text":"أقلامٌ ملوّنٌ"},{"id":"c","text":"أقلامٌ ملوّنةٌ"},{"id":"d","text":"قلمٌ ملوّنةٌ"}]'::jsonb, 'c', 'جمعُ غير العاقل «أقلام» يُوصف بمفردٍ مؤنّثٍ: «أقلامٌ ملوّنةٌ.»؛ فلا نقول «ملوّنون» (للعاقل) ولا «ملوّنٌ» (مفرد مذكّر).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bf60443-a6a3-5572-b5a6-29e5e6b7aaef', '52362a34-1225-5057-ac82-568e14f89c91', 'في «مررتُ بطالبٍ مجتهدٍ»، ما حركة النعت «مجتهدٍ» ولماذا؟', '[{"id":"a","text":"مرفوعٌ، لأنّ النعت يُرفع دائمًا"},{"id":"b","text":"منصوبٌ، لأنّه مفعولٌ به"},{"id":"c","text":"مجرورٌ، تبعًا لمنعوته «طالبٍ» المجرور بحرف الجرّ"},{"id":"d","text":"ساكنٌ، بلا حركة"}]'::jsonb, 'c', 'النعت يتبع منعوته في الحركة؛ و«طالبٍ» مجرورٌ بحرف الجرّ «الباء»، فتبعه النعت «مجتهدٍ» في الجرّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6811aa93-b5cd-543a-9eac-4c4f242b0b86', '52362a34-1225-5057-ac82-568e14f89c91', 'حوّل «وردةٌ حمراءُ» إلى المعرفة مع المطابقة:', '[{"id":"a","text":"الوردةُ حمراءُ"},{"id":"b","text":"وردةُ الحمراءُ"},{"id":"c","text":"الوردُ الأحمرُ"},{"id":"d","text":"الوردةُ الحمراءُ"}]'::jsonb, 'd', 'نُعرّف المنعوت والنعت معًا بإدخال «الـ» على كلٍّ منهما مع بقاء المطابقة في التأنيث: «الوردةُ الحمراءُ.»؛ أمّا «الوردةُ حمراءُ» فاختلّ فيها التطابق في التعريف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'c950ba90-d48f-55e1-bfbb-167854dfe935', 'arabic-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد الصفة والتطابق', 4, 300, 60, 'challenge', 'admin', 4)
