INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b80c67d-f9c0-5d25-b35d-fbf760fbd73c', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'في الجملة «قرأتُ قصّةً مفيدةً ممتعةً.»، ما النعوت للمنعوت «قصّةً»؟', '[{"id":"a","text":"«مفيدةً» و«ممتعةً»، نعتان منصوبان تابعان لها"},{"id":"b","text":"«قرأتُ» فقط"},{"id":"c","text":"لا نعت في الجملة"},{"id":"d","text":"«قصّةً» نعتٌ لنفسها"}]'::jsonb, 'a', 'قد يتعدّد النعت للمنعوت الواحد؛ فـ«مفيدةً» و«ممتعةً» نعتان يصفان «قصّةً» ويتبعانها في التأنيث والتنكير والنصب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a794a182-853b-5a75-960e-d82e8d7d01df', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'اختر الجملة التي طابقَ فيها النعتُ منعوتَه في الأمور الأربعة والحركة معًا:', '[{"id":"a","text":"رأيتُ الفتياتِ المهذّباتُ."},{"id":"b","text":"رأيتُ الفتياتِ المهذّباتِ."},{"id":"c","text":"رأيتُ الفتياتُ المهذّباتِ."},{"id":"d","text":"رأيتُ الفتياتِ المهذّبونَ."}]'::jsonb, 'b', '«الفتياتِ» جمعُ مؤنّثٍ معرفةٌ منصوبٌ (مفعولٌ به، علامة نصبه الكسرة)، فيتبعه النعت «المهذّباتِ» في التأنيث والجمع والتعريف والنصب بالكسرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('825287b3-7887-50c9-9958-64915ae44e13', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'اقرأ: «سلّمتُ على المعلّمينَ الفاضلينَ.» لماذا جاء النعت «الفاضلينَ» بالياء؟', '[{"id":"a","text":"لأنّ النعت يأتي بالياء دائمًا"},{"id":"b","text":"لأنّه فاعلٌ"},{"id":"c","text":"تبع منعوته «المعلّمينَ» جمعَ المذكّرِ السالمَ المجرورَ (يُجرّ بالياء)"},{"id":"d","text":"بلا قاعدة"}]'::jsonb, 'c', '«المعلّمينَ» جمعُ مذكّرٍ سالمٌ مجرورٌ بحرف الجرّ «على» (يُجرّ بالياء)، فتبعه النعت «الفاضلينَ» في الجرّ بالياء؛ فالنعت يطابق منعوته في الحركة ونوعها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e66f3814-68f2-5214-90af-9ff202188ead', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'أيّ تركيبٍ خاطئ في المطابقة رغم ظاهره السليم؟', '[{"id":"a","text":"تلميذٌ نشيطٌ"},{"id":"b","text":"حدائقُ جميلةٌ"},{"id":"c","text":"رجالٌ كرماءُ"},{"id":"d","text":"الكتبُ المفيدونَ"}]'::jsonb, 'd', '«الكتبُ» جمعُ غير عاقلٍ (أشياء) فيُوصف بمفردٍ مؤنّثٍ «المفيدةُ» لا بجمع مذكّرٍ عاقل؛ فـ«الكتبُ المفيدونَ» خطأ، والصواب «الكتبُ المفيدةُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('143eb6e5-e415-5ac4-8aa4-348ee66b67f7', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'في «جاءَ رجلٌ كريمٌ خُلُقُهُ.»، ما إعراب «كريمٌ»؟', '[{"id":"a","text":"مفعولٌ به منصوب"},{"id":"b","text":"فعلٌ ماضٍ"},{"id":"c","text":"فاعلٌ ثانٍ"},{"id":"d","text":"نعتٌ لـ«رجلٌ» مرفوعٌ تابعٌ له في الرفع والتنكير"}]'::jsonb, 'd', '«كريمٌ» يصف «رجلٌ» ويبيّن صفته فهو نعتٌ، تبع منعوته النكرةَ المرفوعَ في الرفع والتنكير؛ و«خُلُقُهُ» فاعلٌ للصفة المشبّهة (تعرّفًا).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e63ab8c0-3e51-550b-8828-b0c355886afd', '39df98e3-83c0-5a5b-b3a7-1fd5e1178b69', 'قال تلميذٌ: «جمع غير العاقل (الأشياء) يُوصف بجمعٍ مثله دائمًا». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ مطلقًا"},{"id":"b","text":"خطأ؛ جمع الأشياء يُوصف بمفردٍ مؤنّثٍ: «جبالٌ شامخةٌ» لا «شامخون»"},{"id":"c","text":"صحيح، يُوصف بجمعِ مذكّرٍ سالم"},{"id":"d","text":"خطأ؛ لا يُوصف جمعُ الأشياء أبدًا"}]'::jsonb, 'b', 'الخطأ الشائع: قياس جمع الأشياء على العاقل. جمعُ غير العاقل يُعامل معاملةَ المفردة المؤنّثة في الوصف: «جبالٌ شامخةٌ»، «كتبٌ مفيدةٌ»، لا «شامخون» ولا «مفيدون».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
