INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3b5f3cc-a48e-5ec0-9369-079df3afe866', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'في «طفلٌ صغيرٌ»، الكلمة التي تصف الاسم هي:', '[{"id":"a","text":"صغيرٌ"},{"id":"b","text":"طفلٌ"},{"id":"c","text":"لا صفة فيها"},{"id":"d","text":"كلاهما موصوف"}]'::jsonb, 'a', '«صغيرٌ» نعتٌ يصف المنعوت «طفلٌ» ويبيّن صفته، وقد طابقه في التذكير والإفراد والتنكير والرفع.', 1)
