  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37e6a4f8-f796-5d2c-9073-75432df4afab', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'أكمل بنعتٍ مطابق: «شجرةٌ ___»:', '[{"id":"a","text":"باسقون"},{"id":"b","text":"باسقةٌ"},{"id":"c","text":"باسقٌ"},{"id":"d","text":"يبسقُ"}]'::jsonb, 'b', '«شجرةٌ» مفردةٌ مؤنّثةٌ نكرة، فيكون نعتها مثلها «باسقةٌ»: «شجرةٌ باسقةٌ.»؛ أمّا «باسقٌ» فمذكّر.', 2)
