  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7f2ad1d-d8bf-5742-95f0-733a5ce244c9', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'أيّ تركيبٍ سليمٌ في وصف المعرفة؟', '[{"id":"a","text":"بيتُ الكبيرُ"},{"id":"b","text":"البيتُ كبيرٌ"},{"id":"c","text":"البيتُ الكبيرُ"},{"id":"d","text":"بيتٌ الكبيرةُ"}]'::jsonb, 'c', 'المنعوت «البيتُ» معرفةٌ فيكون النعت معرفةً مثله «الكبيرُ»: «البيتُ الكبيرُ.»؛ أمّا «البيتُ كبيرٌ» فجملةٌ اسمية (مبتدأ وخبر) لا نعت.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('75949204-d5c8-55e9-abdc-847fdba23fce', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'صحّح: «الوردةُ الجميلُ»:', '[{"id":"a","text":"الوردةُ جميلٌ"},{"id":"b","text":"الوردُ الجميلُ"},{"id":"c","text":"الوردةُ الجميلةُ"},{"id":"d","text":"وردةٌ الجميلُ"}]'::jsonb, 'c', '«الوردةُ» مؤنّثةٌ معرفةٌ فيجب أن يكون نعتها مؤنّثًا معرفةً «الجميلةُ»: «الوردةُ الجميلةُ.»؛ فلا نصف المؤنّث بمذكّر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a4701bd-1559-5d13-b2c3-8e477240e3df', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'في «رأيتُ طائرًا جميلًا»، ما حركة النعت «جميلًا» وسببها؟', '[{"id":"a","text":"مرفوعٌ، لأنّه فاعل"},{"id":"b","text":"مجرورٌ، لأنّه مضافٌ إليه"},{"id":"c","text":"ساكنٌ، بلا سبب"},{"id":"d","text":"منصوبٌ، تبعًا لمنعوته «طائرًا» المنصوبِ (مفعولٌ به)"}]'::jsonb, 'd', 'النعت يتبع منعوته في الحركة؛ و«طائرًا» منصوبٌ (مفعولٌ به) فتبعه النعت «جميلًا» في النصب والتنكير.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('12c80159-e60f-5872-9927-f846d939485c', '3dac698d-b15f-5e14-b25a-ae6a0e2f9ece', 'اقرأ: «اللاعبونَ المجتهدونَ فازوا.» ما الذي طابق فيه النعتُ منعوتَه؟', '[{"id":"a","text":"التأنيث فقط"},{"id":"b","text":"التذكير والجمع والتعريف والرفع جميعًا"},{"id":"c","text":"التنكير فقط"},{"id":"d","text":"لم يطابقه في شيء"}]'::jsonb, 'b', '«اللاعبونَ» جمعُ مذكّرٍ معرفةٍ مرفوعٌ بالواو، فطابقه النعت «المجتهدونَ» في التذكير والجمع والتعريف والرفع بالواو جميعًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

