INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('266245f8-1c0e-504f-bdcd-e1fa631b170d', 'ba182dd0-df82-5891-99ee-d3877a064cc5', 'ما علامة جرّ الاسم بعد حرف الجرّ؟', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"الكسرة"},{"id":"c","text":"الضمّة"},{"id":"d","text":"السكون"}]'::jsonb, 'b', 'الاسم الذي يأتي بعد حرف الجرّ يكون مجرورًا، وعلامة جرّه الأصليّة الكسرة على آخره، مثل «في البيتِ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
