  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4adcafc8-d4f3-514e-a0be-1f0e9fc98d25', 'ba182dd0-df82-5891-99ee-d3877a064cc5', 'أيّ ممّا يلي حرفُ جرٍّ؟', '[{"id":"a","text":"ثمّ"},{"id":"b","text":"الواو"},{"id":"c","text":"على"},{"id":"d","text":"كتبَ"}]'::jsonb, 'c', '«على» حرفُ جرٍّ يجرّ الاسم بعده، أمّا «الواو» و«ثمّ» فأداتا عطفٍ، و«كتبَ» فعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
