  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('028d2164-eea0-5460-a255-77c5e1ffdd3a', 'ba182dd0-df82-5891-99ee-d3877a064cc5', 'في الجملة «ذهبَ التلميذُ إلى المدرسةِ.»، ما الاسم المجرور؟', '[{"id":"a","text":"المدرسةِ"},{"id":"b","text":"التلميذُ"},{"id":"c","text":"ذهبَ"},{"id":"d","text":"إلى"}]'::jsonb, 'a', '«إلى» حرف جرٍّ، فالاسم بعده «المدرسةِ» مجرورٌ بالكسرة، و«التلميذُ» فاعلٌ مرفوع.', 3)
