  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56d436e0-3397-5eeb-aec8-367e7939575d', 'ba182dd0-df82-5891-99ee-d3877a064cc5', 'أيّ أداةٍ تفيد الترتيب مع المُهلة (بعد حين)؟', '[{"id":"a","text":"الواو"},{"id":"b","text":"في"},{"id":"c","text":"على"},{"id":"d","text":"ثمّ"}]'::jsonb, 'd', '«ثمّ» أداةُ عطفٍ تفيد الترتيب مع المهلة: «زرعَ الحبَّ ثمّ حصدَ الثمرَ.»؛ أمّا «الواو» فللجمع بلا ترتيب.', 4)
