INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf25a923-0a0e-544f-adbe-270bdfad1324', 'ba182dd0-df82-5891-99ee-d3877a064cc5', 'في «دخلَ المعلّمُ فوقفَ التلاميذُ.»، ماذا تفيد الفاء؟', '[{"id":"a","text":"الجمع دون ترتيب"},{"id":"b","text":"الترتيب مع التعقيب (بلا مهلة)"},{"id":"c","text":"الظرفيّة"},{"id":"d","text":"الاستعلاء"}]'::jsonb, 'b', '«الفاء» تفيد الترتيب مع التعقيب؛ فالوقوف جاء عقب الدخول مباشرةً بلا مهلة، بخلاف «ثمّ» التي فيها تراخٍ.', 5)
