INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c9d15c1-1306-583c-8df6-13585c8fc7cf', '416c6c0f-2afa-528e-afd4-5fcd23e53e94', 'في «الكتابُ في الحقيبةِ.»، ما الاسم المجرور؟', '[{"id":"a","text":"الكتابُ"},{"id":"b","text":"الحقيبةِ"},{"id":"c","text":"في"},{"id":"d","text":"لا اسم مجرور"}]'::jsonb, 'b', '«في» حرف جرٍّ، فالاسم بعده «الحقيبةِ» مجرورٌ بالكسرة، و«الكتابُ» مبتدأٌ مرفوع.', 2)
