INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc469c24-7c15-553f-abfd-c10f29377c49', '416c6c0f-2afa-528e-afd4-5fcd23e53e94', 'أيّ أداةٍ تفيد الجمع دون ترتيب؟', '[{"id":"a","text":"الواو"},{"id":"b","text":"ثمّ"},{"id":"c","text":"الفاء"},{"id":"d","text":"إلى"}]'::jsonb, 'a', '«الواو» أداةُ عطفٍ تفيد الجمع المطلق دون ترتيب: «جاءَ سعدٌ وخالدٌ.»؛ أمّا «ثمّ» و«الفاء» ففيهما ترتيب.', 4)
