INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e42f90f8-8349-5feb-86da-22aabd8adef1', '1c2dd3c5-55a3-55ee-a253-8329869420e3', 'في «وقفَ الطائرُ على الغصنِ.»، عيّن حرف الجرّ والاسم المجرور:', '[{"id":"a","text":"حرف الجرّ «على»، والمجرور «الغصنِ»"},{"id":"b","text":"حرف الجرّ «الغصنِ»، والمجرور «على»"},{"id":"c","text":"حرف الجرّ «وقفَ»"},{"id":"d","text":"لا حرف جرٍّ في الجملة"}]'::jsonb, 'a', '«على» حرف جرٍّ يفيد الاستعلاء، والاسم بعده «الغصنِ» مجرورٌ بالكسرة، و«الطائرُ» فاعلٌ مرفوع.', 1)
