INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad12896e-f3d3-5f01-9b0d-446cad468bcc', '1c2dd3c5-55a3-55ee-a253-8329869420e3', 'أيّ جملةٍ ضبطتِ الاسمَ المجرور ضبطًا صحيحًا؟', '[{"id":"a","text":"ذهبتُ إلى الحديقةُ."},{"id":"b","text":"ذهبتُ إلى الحديقةَ."},{"id":"c","text":"ذهبتُ إلى الحديقةِ."},{"id":"d","text":"ذهبتُ إلى الحديقةْ."}]'::jsonb, 'c', 'بعد حرف الجرّ «إلى» يكون الاسم مجرورًا بالكسرة: «إلى الحديقةِ.»؛ أمّا الضمّة والفتحة والسكون فليست علامةَ جرٍّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dd1ab24-1ebe-5c23-ad5d-990bd962928e', '1c2dd3c5-55a3-55ee-a253-8329869420e3', 'ما معنى حرف الجرّ «في» في «النجومُ في السماءِ.»؟', '[{"id":"a","text":"الاستعانة"},{"id":"b","text":"ابتداء الغاية"},{"id":"c","text":"انتهاء الغاية"},{"id":"d","text":"الظرفيّة (المكان)"}]'::jsonb, 'd', '«في» تفيد الظرفيّة (المكان أو الزمان)؛ فالنجوم داخل السماء، فهي ظرفُ مكانٍ لها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4320bff3-70a9-5509-8389-3cd2640f5864', '1c2dd3c5-55a3-55ee-a253-8329869420e3', 'اقرأ: «أكلَ الطفلُ التفّاحةَ ثمّ الموزةَ.» ما الذي عطفته «ثمّ»؟', '[{"id":"a","text":"«الموزةَ» على «التفّاحةَ» (مع الترتيب والمهلة)"},{"id":"b","text":"«الطفلُ» على «أكلَ»"},{"id":"c","text":"لا عطف في الجملة"},{"id":"d","text":"«أكلَ» على «الموزةَ»"}]'::jsonb, 'a', '«ثمّ» عطفت المفعول «الموزةَ» على المفعول «التفّاحةَ» مع إفادة الترتيب والمهلة، فاشتركا في كونهما مأكولين منصوبين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('811b4b1b-a23c-5a51-925d-9ae86084c344', '1c2dd3c5-55a3-55ee-a253-8329869420e3', 'قال تلميذٌ: «الواو والفاء وثمّ كلّها بمعنًى واحد». ما الصحيح؟', '[{"id":"a","text":"صحيح، لا فرق بينها"},{"id":"b","text":"صحيح، كلّها تفيد الترتيب"},{"id":"c","text":"خطأ؛ الواو جمعٌ بلا ترتيب، والفاء ترتيبٌ وتعقيب، وثمّ ترتيبٌ مع مهلة"},{"id":"d","text":"خطأ؛ كلّها حروف جرٍّ"}]'::jsonb, 'c', 'الخطأ الشائع: التسوية بينها. لكلٍّ معنًى: «الواو» للجمع المطلق، «الفاء» للترتيب والتعقيب الفوريّ، «ثمّ» للترتيب مع المهلة؛ فنختار حسب المعنى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'cd792bd7-06ae-50eb-811e-0fc4ddc757ed', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): أدوات الربط والجرّ', 2, 75, 15, 'practice', 'admin', 3)
