INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79df8d7d-2311-5204-973a-145de083601a', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'أيّ مجموعةٍ كلُّها حروفُ جرٍّ؟', '[{"id":"a","text":"الواو، الفاء، ثمّ"},{"id":"b","text":"مِن، إلى، على"},{"id":"c","text":"كتبَ، يلعبُ، نامَ"},{"id":"d","text":"الذي، التي، مَن"}]'::jsonb, 'b', '«مِن، إلى، على» حروفُ جرٍّ تجرّ الاسم بعدها؛ أمّا «الواو، الفاء، ثمّ» فأدوات عطف، والباقي أفعالٌ أو أسماء موصولة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('274fea32-3468-582e-994c-f43ee7a51c92', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'أكمل: «اللوحةُ ___ الجدارِ.» بحرف جرٍّ يفيد الاستعلاء:', '[{"id":"a","text":"في"},{"id":"b","text":"على"},{"id":"c","text":"ثمّ"},{"id":"d","text":"من"}]'::jsonb, 'b', '«على» تفيد الاستعلاء (فوق): «اللوحةُ على الجدارِ.»؛ أمّا «في» فللظرفيّة و«من» لابتداء الغاية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef1f1ef2-f061-5a3f-8ba2-de679d91ed41', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'في «خرجَ الفلّاحُ من الحقلِ.»، ما إعراب «الحقلِ»؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"مفعولٌ به منصوب"},{"id":"c","text":"اسمٌ مجرورٌ بالكسرة بعد حرف الجرّ «من»"},{"id":"d","text":"نعتٌ مرفوع"}]'::jsonb, 'c', '«من» حرف جرٍّ، فالاسم بعده «الحقلِ» مجرورٌ وعلامة جرّه الكسرة، و«الفلّاحُ» فاعلٌ مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('243c3657-895f-5fbd-9652-3dac7f7ed00a', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'اختر الأداة المناسبة: «استيقظَ ___ صلّى» (ترتيبٌ وتعقيبٌ فوريّ):', '[{"id":"a","text":"الواو"},{"id":"b","text":"في"},{"id":"c","text":"على"},{"id":"d","text":"فـ (الفاء)"}]'::jsonb, 'd', '«الفاء» تفيد الترتيب مع التعقيب الفوريّ: «استيقظَ فصلّى.»؛ فالصلاة عقب الاستيقاظ مباشرةً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a14e7a29-8f74-52ea-a5b9-e71fa45224cf', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'أيّ جملةٍ استُعملت فيها «ثمّ» استعمالًا صحيحًا في المعنى؟', '[{"id":"a","text":"وُلدَ الطفلُ ثمّ كبرَ وصارَ شابًّا."},{"id":"b","text":"جلسَ ثمّ في نفس اللحظة قامَ معًا."},{"id":"c","text":"كتبَ ثمّ بالقلمِ."},{"id":"d","text":"ذهبَ ثمّ السوقِ."}]'::jsonb, 'a', '«ثمّ» للترتيب مع المهلة، ويناسب تتابع الأحداث المتباعدة: «وُلدَ الطفلُ ثمّ كبرَ.»؛ أمّا البقيّة فخلطت معناها بمعاني الجرّ أو ناقضت المهلة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('148c56e3-edde-5c1d-b5e0-45b56fd76d2d', 'a29f0bbf-3ce5-5f4e-9e04-77d2dd0b6be1', 'ما معنى حرف الجرّ «الباء» في «قطعَ الخبزَ بالسكّينِ.»؟', '[{"id":"a","text":"انتهاء الغاية"},{"id":"b","text":"الظرفيّة"},{"id":"c","text":"ابتداء الغاية"},{"id":"d","text":"الاستعانة (الأداة)"}]'::jsonb, 'd', '«الباء» تفيد الاستعانة؛ فالسكّينُ أداةُ القطع: «قطعَ بالسكّينِ.»، و«السكّينِ» مجرورٌ بالكسرة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

