  ('a7557508-0964-5ce4-8142-de402cc8c87f', 'cd792bd7-06ae-50eb-811e-0fc4ddc757ed', 'arabic-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد أدوات الربط', 4, 300, 60, 'challenge', 'admin', 4)
