INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d8863ac-b2ed-54c2-95e9-9e25d5fcfd45', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'اقرأ: «انطلقَ القطارُ من المحطّةِ إلى المدينةِ.» كم اسمًا مجرورًا في الجملة؟', '[{"id":"a","text":"اسمان: «المحطّةِ» و«المدينةِ»"},{"id":"b","text":"اسمٌ واحد"},{"id":"c","text":"ثلاثة أسماء"},{"id":"d","text":"لا اسم مجرور"}]'::jsonb, 'a', 'حرفان للجرّ في الجملة: «من» جرّت «المحطّةِ» (ابتداء الغاية)، و«إلى» جرّت «المدينةِ» (انتهاء الغاية)؛ فالمجروران اثنان وكلاهما بالكسرة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84297df4-7f03-5b92-ab2d-4f1bab0f2b05', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'اختر الجملة التي راعت معاني الأدوات الثلاث (جمعٌ، فتعقيبٌ، فمهلة) ترتيبًا:', '[{"id":"a","text":"حضرَ الضيوفُ ثمّ جلسوا وانصرفوا فاستراحوا."},{"id":"b","text":"حضرَ الضيوفُ فاستراحوا ثمّ جلسوا وانصرفوا."},{"id":"c","text":"حضرَ الضيوفُ على جلسوا في انصرفوا."},{"id":"d","text":"حضرَ الضيوفُ وجلسوا فاستراحوا ثمّ انصرفوا."}]'::jsonb, 'd', 'المعنى المنطقيّ: حضورٌ وجلوسٌ معًا (الواو)، فاستراحةٌ عقبه (الفاء)، ثمّ انصرافٌ بعد مهلة (ثمّ): «حضرَ الضيوفُ وجلسوا فاستراحوا ثمّ انصرفوا.»', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1163bb3-f107-5e4a-82f4-af7ac24586b6', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'في «مررتُ بالحديقةِ الجميلةِ.»، ما إعراب «الجميلةِ»؟', '[{"id":"a","text":"مفعولٌ به منصوب"},{"id":"b","text":"فاعلٌ مرفوع"},{"id":"c","text":"نعتٌ مجرورٌ تابعٌ لـ«الحديقةِ» المجرورةِ بالكسرة"},{"id":"d","text":"حرفُ جرّ"}]'::jsonb, 'c', '«الباء» جرّت «الحديقةِ»، و«الجميلةِ» نعتٌ يتبع منعوته في الجرّ بالكسرة؛ فاجتمع هنا حرفُ الجرّ والنعتُ التابع للمجرور.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b28fe76-de25-5913-9355-917438bc981e', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'أيّ جملةٍ استُعملت فيها «الفاء» استعمالًا صحيحًا (ترتيبٌ وتعقيب)؟', '[{"id":"a","text":"وصلَ المطرُ فجفَّتِ الأرضُ."},{"id":"b","text":"لمسَ النارَ فأبعدَ يدَهُ مسرعًا."},{"id":"c","text":"كبرَ فوُلدَ."},{"id":"d","text":"نضجَ الزرعُ فزُرعَ."}]'::jsonb, 'b', '«الفاء» تفيد ترتيبًا وتعقيبًا منطقيًّا: «لمسَ النارَ فأبعدَ يدَهُ»؛ أمّا «كبرَ فوُلدَ» و«نضجَ فزُرعَ» فعكستا الترتيب الطبيعيّ، و«وصلَ المطرُ فجفَّتِ» ناقضت السبب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ab10b0d-4355-5f33-97ad-e1a3e09613ad', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'اقرأ: «كتبَ الرسالةَ بخطٍّ جميلٍ في المساءِ.» ما معاني الحرفين «الباء» و«في»؟', '[{"id":"a","text":"كلاهما لانتهاء الغاية"},{"id":"b","text":"«الباء» للاستعلاء، و«في» لابتداء الغاية"},{"id":"c","text":"«الباء» للاستعانة (الأداة/الوصف)، و«في» للظرفيّة الزمانيّة"},{"id":"d","text":"لا معنى لهما"}]'::jsonb, 'c', '«بخطٍّ» الباء فيها للاستعانة/الوصف (وصف كيفيّة الكتابة)، و«في المساءِ» تفيد الظرفيّة الزمانيّة (وقت الفعل)، وكلا الاسمين مجرورٌ بالكسرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29aab734-2939-5ba0-8eab-31b4e609549b', 'a7557508-0964-5ce4-8142-de402cc8c87f', 'قال تلميذٌ: «كلّ اسمٍ مكسورِ الآخرِ يكون مجرورًا بحرف جرّ». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ دائمًا"},{"id":"b","text":"خطأ؛ قد يكون الجرّ بالإضافة لا بالحرف (كتابُ التلميذِ)، فلا يلزم وجود حرف جرّ"},{"id":"c","text":"صحيح، لا جرّ إلّا بالحرف"},{"id":"d","text":"خطأ؛ المجرور لا يُكسر آخره"}]'::jsonb, 'b', 'الجرّ يكون بحرف الجرّ، وأيضًا بالإضافة؛ ففي «كتابُ التلميذِ» جُرَّ «التلميذِ» بالإضافة لا بحرفٍ، فالكسرةُ علامةُ جرٍّ سببُها قد لا يكون حرفًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

