INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9222d892-5881-5f05-8909-f5d251528fe3', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'في «نامَ القطُّ تحتَ الشجرةِ.»، ما الاسم المجرور بحرف الجرّ؟', '[{"id":"a","text":"الشجرةِ"},{"id":"b","text":"القطُّ"},{"id":"c","text":"نامَ"},{"id":"d","text":"تحتَ"}]'::jsonb, 'a', '«الشجرةِ» اسمٌ مجرورٌ بالكسرة (سبقه ما يقتضي الجرّ في تركيب المكان)، و«القطُّ» فاعلٌ مرفوعٌ بالضمّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e1dc969-d721-51a0-a4db-8ca6b35e57eb', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'أيّ ممّا يلي أداةُ عطفٍ لا حرفُ جرّ؟', '[{"id":"a","text":"إلى"},{"id":"b","text":"في"},{"id":"c","text":"على"},{"id":"d","text":"ثمّ"}]'::jsonb, 'd', '«ثمّ» أداةُ عطفٍ تربط بين شيئين مع الترتيب والمهلة، أمّا «إلى، في، على» فحروفُ جرٍّ تجرّ الاسم بعدها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e88668c5-e572-51e2-aea1-c3e7787c35dd', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'أكمل بحرف جرٍّ يفيد ابتداء الغاية: «بدأَ المطرُ ___ الصباحِ.»', '[{"id":"a","text":"على"},{"id":"b","text":"الواو"},{"id":"c","text":"مِن"},{"id":"d","text":"ثمّ"}]'::jsonb, 'c', '«مِن» تفيد ابتداء الغاية (الزمانيّة هنا): «بدأَ المطرُ من الصباحِ.»؛ أمّا «على» فللاستعلاء و«ثمّ/الواو» عطف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a7d21c6-8a45-5ff0-9752-72a61a178fe1', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'في «شربَ الماءَ فشكرَ اللهَ.»، ماذا أفادتِ الفاء؟', '[{"id":"a","text":"الجمع دون ترتيب"},{"id":"b","text":"المهلة الطويلة"},{"id":"c","text":"الظرفيّة"},{"id":"d","text":"الترتيب مع التعقيب (الشكر عقب الشرب)"}]'::jsonb, 'd', '«الفاء» تفيد الترتيب مع التعقيب الفوريّ؛ فالشكر جاء عقب الشرب مباشرةً، لا مع مهلةٍ كما في «ثمّ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('887ff000-063a-5356-9fda-ea4d9c38a1f3', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'اقرأ: «سافرَ الحجّاجُ من تونسَ إلى مكّةَ بالطائرةِ.» عيّن معنى «الباء» في «بالطائرةِ»:', '[{"id":"a","text":"الاستعانة (وسيلة السفر)"},{"id":"b","text":"الظرفيّة الزمانيّة"},{"id":"c","text":"ابتداء الغاية"},{"id":"d","text":"الاستعلاء"}]'::jsonb, 'a', '«الباء» في «بالطائرةِ» للاستعانة؛ فالطائرةُ وسيلةُ السفر، و«الطائرةِ» اسمٌ مجرورٌ بالكسرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('826bf349-7d05-507c-8a0b-440d8b63ad21', '011a117b-02d3-5bde-b66d-31ab2d3db75d', 'اقرأ: «دقَّ الجرسُ فدخلَ التلاميذُ ثمّ بدأَ الدرسُ.» ما الفرق بين «الفاء» و«ثمّ» هنا؟', '[{"id":"a","text":"لا فرق، كلاهما للجمع"},{"id":"b","text":"«الفاء» للتعقيب الفوريّ (الدخول عقب الجرس)، و«ثمّ» للترتيب مع مهلة (بدء الدرس بعد حين)"},{"id":"c","text":"«الفاء» للمهلة و«ثمّ» للتعقيب الفوريّ"},{"id":"d","text":"كلاهما حرفُ جرّ"}]'::jsonb, 'b', '«الفاء» تفيد التعقيب الفوريّ: دخلوا فور دقّ الجرس؛ و«ثمّ» تفيد الترتيب مع مهلة: بدأ الدرس بعد دخولهم بقليل، فالأداتان مختلفتان في المعنى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

