INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6ab5c97-6638-5624-adac-05f8a67c36cc', '89ecd518-b52b-5cbe-847e-b9cad502a1ea', 'الفعل الماضي يدلّ على حدثٍ:', '[{"id":"a","text":"يجري الآن"},{"id":"b","text":"سيجري في المستقبل"},{"id":"c","text":"وقعَ وانتهى قبل التكلّم"},{"id":"d","text":"مطلوبٍ حدوثه"}]'::jsonb, 'c', 'الفعل الماضي يدلّ على حدثٍ وقعَ وانتهى قبل زمن التكلّم، مثل «كتبَ» و«سافرَ أمسِ».', 1)
