INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11023579-dc70-5817-98de-c17dedeadc70', '89ecd518-b52b-5cbe-847e-b9cad502a1ea', 'ما حروف المضارعة المجموعة في كلمة «أنيت»؟', '[{"id":"a","text":"الألف واللام والميم"},{"id":"b","text":"الهمزة والنون والياء والتاء"},{"id":"c","text":"الباء والكاف واللام"},{"id":"d","text":"السين والتاء والميم"}]'::jsonb, 'b', 'حروف المضارعة أربعة مجموعةٌ في «أنيت»: الهمزة (أكتبُ)، النون (نكتبُ)، الياء (يكتبُ)، التاء (تكتبُ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88e7b13a-466d-59dc-bc51-eb4ad742f8ce', '89ecd518-b52b-5cbe-847e-b9cad502a1ea', 'أيّ الأفعال التالية فعلُ أمرٍ؟', '[{"id":"a","text":"كتبَ"},{"id":"b","text":"يكتبُ"},{"id":"c","text":"اكتبْ"},{"id":"d","text":"كاتبٌ"}]'::jsonb, 'c', '«اكتبْ» فعلُ أمرٍ يدلّ على طلبِ الكتابة، أمّا «كتبَ» فماضٍ و«يكتبُ» مضارعٌ و«كاتبٌ» اسمٌ لا فعل.', 3)
