INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18a4f78d-f38e-53f9-832f-b27676b26f1a', '89ecd518-b52b-5cbe-847e-b9cad502a1ea', 'ما زمن الفعل «يلعبُ»؟', '[{"id":"a","text":"ماضٍ"},{"id":"b","text":"أمرٌ"},{"id":"c","text":"ليس فعلًا"},{"id":"d","text":"مضارعٌ، لأنّه بدأ بالياء (من حروف «أنيت»)"}]'::jsonb, 'd', '«يلعبُ» بدأ بالياء وهي من حروف المضارعة «أنيت»، فهو فعلٌ مضارعٌ يدلّ على حدثٍ يجري أو سيجري.', 4)
