INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d25a3c3-20d1-53ea-9437-9b8d8f843f47', 'facbf212-340c-5393-aff6-999ddb39181e', 'في «لعبتِ البنتُ.»، ما الذي دلّ على أنّ الفعل ماضٍ مؤنّث؟', '[{"id":"a","text":"حرف مضارعة في أوّله"},{"id":"b","text":"كونه طلبًا"},{"id":"c","text":"كونه اسمًا"},{"id":"d","text":"تاء التأنيث الساكنة في آخره (لعبتْ)"}]'::jsonb, 'd', 'الفعل الماضي تلحقه تاءُ التأنيث الساكنة مع الفاعل المؤنّث: «لعبتْ»، وهذه علامةٌ تدلّ على أنّه ماضٍ وفاعله مؤنّث.', 6)
