INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da246408-2ecf-5148-bbb9-e3f815da6abe', 'e0491f89-8f1b-5ec0-ba2d-b2a578689696', 'اقرأ: «خرجَ من البيتِ، ويمشي في الطريقِ، وسيصلُ قريبًا.» ما زمن «يمشي»؟', '[{"id":"a","text":"مضارعٌ (بدأ بالياء، يجري الآن)"},{"id":"b","text":"ماضٍ"},{"id":"c","text":"أمرٌ"},{"id":"d","text":"اسمٌ"}]'::jsonb, 'a', '«يمشي» بدأ بالياء من حروف «أنيت» ويدلّ على حدثٍ يجري الآن، فهو فعلٌ مضارع، بينما «خرجَ» ماضٍ.', 1)
