INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34a8222a-257f-5d9a-a639-00bce0ffa58e', 'e0491f89-8f1b-5ec0-ba2d-b2a578689696', 'أيّ صفٍّ صرّفَ الفعل في الأزمنة الثلاثة ترتيبًا صحيحًا (ماضٍ، مضارع، أمر)؟', '[{"id":"a","text":"يجلسُ — اجلسْ — جلسَ"},{"id":"b","text":"اجلسْ — جلسَ — يجلسُ"},{"id":"c","text":"جلسَ — يجلسُ — اجلسْ"},{"id":"d","text":"جالسٌ — جلوسٌ — مجلسٌ"}]'::jsonb, 'c', 'الترتيب الصحيح: ماضٍ «جلسَ» ثمّ مضارع «يجلسُ» ثمّ أمر «اجلسْ»؛ أمّا الخيار (د) فأسماءٌ لا أفعال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aba2a443-1ad5-5a69-a39b-8a64c72d790c', 'e0491f89-8f1b-5ec0-ba2d-b2a578689696', 'في «اكتبي واجبَكِ يا مريمُ.»، ما زمن «اكتبي»؟', '[{"id":"a","text":"ماضٍ"},{"id":"b","text":"مضارعٌ"},{"id":"c","text":"اسمٌ"},{"id":"d","text":"أمرٌ (طلبٌ، ولحقته ياءُ المخاطبة)"}]'::jsonb, 'd', '«اكتبي» فعلُ أمرٍ يطلب الكتابة من المخاطَبة، وقد لحقته ياءُ المخاطبة الدالّة على المؤنّثة، فهو أمرٌ لا مضارع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdc1b23b-3fc2-5add-aa7c-5f6d3aaf6052', 'e0491f89-8f1b-5ec0-ba2d-b2a578689696', 'أيّ جملةٍ فعلُها ماضٍ رغم دلالة سياقها على عادةٍ متكرّرة؟', '[{"id":"a","text":"يستيقظُ مبكّرًا كلَّ يومٍ."},{"id":"b","text":"نهضَ الطفلُ من نومِهِ صباحَ أمسِ."},{"id":"c","text":"انهضْ مبكّرًا."},{"id":"d","text":"ناهضٌ نشيطٌ."}]'::jsonb, 'b', '«نهضَ» فعلٌ ماضٍ (وقعَ وانتهى، آخره مفتوح)، وقرينة «صباحَ أمسِ» تؤكّد المضيّ؛ أمّا «يستيقظُ» فمضارعٌ و«انهضْ» أمر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('707d57b0-c7eb-5869-9584-6aefb2453040', 'e0491f89-8f1b-5ec0-ba2d-b2a578689696', 'قال تلميذٌ: «كلّ فعلٍ يبدأ بهمزةٍ فهو فعلُ أمرٍ». ما الصحيح؟', '[{"id":"a","text":"صحيح، الهمزة علامةُ الأمر"},{"id":"b","text":"صحيح، كلّ مهموزٍ أمرٌ"},{"id":"c","text":"خطأ؛ قد تكون الهمزةُ حرفَ مضارعةٍ للمتكلّم (أكتبُ)، فالعبرة بالعلامة والمعنى"},{"id":"d","text":"خطأ؛ لا يبدأ فعلٌ بهمزة"}]'::jsonb, 'c', 'الخطأ الشائع: الحكم بالهمزة وحدها. الهمزة قد تكون حرفَ مضارعةٍ للمتكلّم «أكتبُ، أقرأُ» (مضارع)، وقد تكون همزةَ وصلٍ في الأمر «اكتبْ»؛ فنميّز بالعلامة والمعنى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

