  ('73d998b7-e989-5657-90b1-be6ee9dcde4d', '76e9daaa-eb20-58c8-ac32-7c74c36b98f0', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): أزمنة الفعل', 2, 75, 15, 'practice', 'admin', 3)
