INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72691d09-84ee-55ae-905f-282f8af60845', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'صنّف الفعل «نكتبُ» حسب زمنه:', '[{"id":"a","text":"ماضٍ"},{"id":"b","text":"مضارعٌ (بدأ بالنون)"},{"id":"c","text":"أمرٌ"},{"id":"d","text":"اسمٌ"}]'::jsonb, 'b', '«نكتبُ» بدأ بالنون من حروف المضارعة «أنيت»، فهو مضارعٌ يدلّ على المتكلّمين (نحن).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
