  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b6a8224-d3da-5482-b82f-9c430578e7f7', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'أكمل بفعلٍ ماضٍ مناسب: «أمسِ ___ التلميذُ درسَهُ.»', '[{"id":"a","text":"حفظَ"},{"id":"b","text":"يحفظُ"},{"id":"c","text":"احفظْ"},{"id":"d","text":"حافظٌ"}]'::jsonb, 'a', 'قرينة «أمسِ» تدلّ على المضيّ، فنختار الماضي «حفظَ»: «أمسِ حفظَ التلميذُ درسَهُ.»؛ أمّا «يحفظُ» فمضارعٌ و«احفظْ» أمر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfc7ca3b-e2ee-5675-832a-0857462f1e76', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'حوّل «يلعبُ» إلى فعل أمرٍ:', '[{"id":"a","text":"لعبَ"},{"id":"b","text":"لاعبٌ"},{"id":"c","text":"العبْ"},{"id":"d","text":"يلاعبُ"}]'::jsonb, 'c', 'من المضارع «يلعبُ» نصنع الأمر بحذف حرف المضارعة والطلب: «العبْ»؛ أمّا «لعبَ» فماضٍ و«لاعبٌ» اسم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
