  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2b9f63c-e251-5d86-8444-1f454a3aa6ca', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'أيّ جملةٍ فعلُها مضارعٌ؟', '[{"id":"a","text":"كتبَ الواجبَ."},{"id":"b","text":"اكتبِ الواجبَ."},{"id":"c","text":"كاتبُ الواجبِ مجتهدٌ."},{"id":"d","text":"يكتبُ الواجبَ بخطٍّ جميلٍ."}]'::jsonb, 'd', '«يكتبُ» بدأ بالياء من حروف «أنيت» فهو مضارع؛ أمّا «كتبَ» فماضٍ و«اكتبِ» أمرٌ و«كاتبُ» اسم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c41aec5b-7709-5ca7-afda-4b294186007b', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'ما ماضي الفعل المضارع «يذهبُ»؟', '[{"id":"a","text":"اذهبْ"},{"id":"b","text":"ذاهبٌ"},{"id":"c","text":"ذهابٌ"},{"id":"d","text":"ذهبَ"}]'::jsonb, 'd', 'نحذف حرف المضارعة من «يذهبُ» ونجعله ماضيًا مفتوح الآخر: «ذهبَ»؛ أمّا «اذهبْ» فأمرٌ و«ذاهبٌ» اسمُ فاعل.', 5)
