  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2c22649-4770-5d7e-8758-59e0a3f1ec4c', '73d998b7-e989-5657-90b1-be6ee9dcde4d', 'في «اشربْ ثمّ نمْ مبكّرًا.»، كم فعلَ أمرٍ في الجملة؟', '[{"id":"a","text":"فعلٌ واحد"},{"id":"b","text":"فعلان: «اشربْ» و«نمْ»"},{"id":"c","text":"لا فعل أمرٍ"},{"id":"d","text":"ثلاثة أفعال"}]'::jsonb, 'b', '«اشربْ» و«نمْ» كلاهما فعلُ أمرٍ يدلّ على الطلب، و«ثمّ» أداةُ عطفٍ تربط بينهما مع المهلة؛ فأفعال الأمر اثنان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

