INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79404afe-4829-5bcb-8629-8270f3778794', 'd0029091-bb18-556c-a173-c758fd41f794', 'اقرأ: «استيقظَ سعدٌ، ويتناولُ فطورَهُ، ثمّ سيذهبُ إلى المدرسةِ.» صنّف الأفعال الثلاثة بالترتيب:', '[{"id":"a","text":"ماضٍ، مضارع، مضارع (يدلّ على المستقبل بقرينة سيذهبُ)"},{"id":"b","text":"ماضٍ، أمر، ماضٍ"},{"id":"c","text":"أمر، أمر، أمر"},{"id":"d","text":"مضارع، ماضٍ، أمر"}]'::jsonb, 'a', '«استيقظَ» ماضٍ، و«يتناولُ» مضارعٌ (الياء)، و«سيذهبُ» مضارعٌ دخلت عليه السين فدلّ على المستقبل؛ فالأفعال: ماضٍ، فمضارعان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6e6dec0-bca2-5074-a47c-56505ca9505d', 'd0029091-bb18-556c-a173-c758fd41f794', 'ما الأمر من الفعل المضارع «تقرأُ»، ومن «تأكلُ»؟', '[{"id":"a","text":"قرأَ — أكلَ"},{"id":"b","text":"اقرأْ — كُلْ"},{"id":"c","text":"يقرأُ — يأكلُ"},{"id":"d","text":"قارئٌ — آكلٌ"}]'::jsonb, 'b', 'أمرُ «تقرأُ» هو «اقرأْ»، وأمرُ «تأكلُ» هو «كُلْ» (حُذفت همزته في الأمر)؛ فكلاهما طلبٌ، أمّا (أ) فماضيان و(د) اسمان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91b8a16b-1749-5c81-968c-e7767d608e69', 'd0029091-bb18-556c-a173-c758fd41f794', 'في «نمْ مبكّرًا تستيقظْ نشيطًا.»، ما زمنا «نمْ» و«تستيقظْ»؟', '[{"id":"a","text":"كلاهما ماضٍ"},{"id":"b","text":"كلاهما اسمٌ"},{"id":"c","text":"«نمْ» أمرٌ، و«تستيقظْ» مضارعٌ (بدأ بالتاء)"},{"id":"d","text":"«نمْ» مضارعٌ، و«تستيقظْ» أمرٌ"}]'::jsonb, 'c', '«نمْ» فعلُ أمرٍ (طلبٌ، ساكنُ الآخر)، و«تستيقظْ» مضارعٌ بدأ بالتاء من حروف «أنيت»؛ فلا نخلط بينهما رغم تجاورهما.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5136394b-877d-55c7-8326-f9944e1265cd', 'd0029091-bb18-556c-a173-c758fd41f794', 'أيّ الأفعال ماضٍ، رغم أنّ آخره ليس مفتوحًا ظاهرًا؟', '[{"id":"a","text":"ينجحُ"},{"id":"b","text":"انجحْ"},{"id":"c","text":"ناجحٌ"},{"id":"d","text":"نجحتْ (بتاء التأنيث الساكنة)"}]'::jsonb, 'd', '«نجحتْ» فعلٌ ماضٍ لحقته تاءُ التأنيث الساكنة مع الفاعل المؤنّث؛ فالتاء الساكنة في آخره علامةُ ماضٍ مؤنّث، لا مضارع ولا أمر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eff51e37-f6d0-52ac-8b95-a5645b9a23e7', 'd0029091-bb18-556c-a173-c758fd41f794', 'اقرأ: «العبوا بالكرةِ.» ما زمن «العبوا»؟', '[{"id":"a","text":"فعلٌ ماضٍ"},{"id":"b","text":"فعلٌ مضارع"},{"id":"c","text":"فعلُ أمرٍ موجّهٌ لجماعةٍ (طلبُ اللعب منهم)"},{"id":"d","text":"اسمٌ"}]'::jsonb, 'c', '«العبوا» فعلُ أمرٍ متّصلٌ بواو الجماعة، يطلب اللعب من جماعة المخاطبين؛ فهو أمرٌ لا ماضٍ ولا مضارع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afd47463-f370-5683-a630-6001e1feccc2', 'd0029091-bb18-556c-a173-c758fd41f794', 'قال تلميذٌ: «الفعل المبدوء بالتاء يكون دائمًا فعلَ أمرٍ». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ دائمًا"},{"id":"b","text":"خطأ؛ التاء من حروف المضارعة «أنيت»، فالمبدوء بها مضارعٌ غالبًا (تكتبُ، تلعبُ)"},{"id":"c","text":"صحيح، التاء علامةُ الأمر"},{"id":"d","text":"خطأ؛ لا يبدأ فعلٌ بالتاء"}]'::jsonb, 'b', 'الخطأ الشائع: ظنّ التاء علامةَ أمر. التاء حرفُ مضارعةٍ في «أنيت»، فالفعل المبدوء بها مضارعٌ غالبًا «تكتبُ، تشربُ»؛ وفعل الأمر يبدأ غالبًا بهمزة الوصل «اكتبْ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

