INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c37d00be-839d-5bfa-8c7b-f14b26d228d8', '3787ec36-4885-5684-b285-c05dd9206bb0', 'أيّ فعلٍ مضارعٌ بدأ بهمزة المضارعة (المتكلّم)؟', '[{"id":"a","text":"اكتبْ"},{"id":"b","text":"أكتبُ"},{"id":"c","text":"كتبَ"},{"id":"d","text":"كاتبٌ"}]'::jsonb, 'b', '«أكتبُ» مضارعٌ بدأ بهمزة المضارعة من «أنيت» ويدلّ على المتكلّم (أنا)؛ أمّا «اكتبْ» فأمرٌ بهمزة الوصل و«كتبَ» ماضٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bdab971f-4b46-5525-9e88-589f5f92490a', '3787ec36-4885-5684-b285-c05dd9206bb0', 'حوّل الماضي «نظرَ» إلى المضارع:', '[{"id":"a","text":"انظرْ"},{"id":"b","text":"ناظرٌ"},{"id":"c","text":"ينظرُ"},{"id":"d","text":"نظرَ"}]'::jsonb, 'c', 'بزيادة حرف مضارعةٍ في أوّل «نظرَ» نحصل على المضارع «ينظرُ»؛ أمّا «انظرْ» فأمرٌ و«ناظرٌ» اسمُ فاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f165d593-a2a9-542f-836c-c509e081dd8b', '3787ec36-4885-5684-b285-c05dd9206bb0', 'في «تشربُ القطّةُ الحليبَ.»، ما زمن «تشربُ»؟', '[{"id":"a","text":"ماضٍ"},{"id":"b","text":"أمرٌ"},{"id":"c","text":"مضارعٌ (بدأ بالتاء، والفاعل مؤنّث)"},{"id":"d","text":"اسمٌ"}]'::jsonb, 'c', '«تشربُ» بدأ بالتاء من حروف «أنيت» فهو مضارع، والتاء هنا لمضارعةِ الغائبة المؤنّثة (هي القطّةُ)؛ فهو مضارعٌ لا ماضٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e180cc8-5c6f-595d-b479-230ff5ce03a7', '3787ec36-4885-5684-b285-c05dd9206bb0', 'اقرأ: «اقرأْ كلَّ يومٍ تزددْ علمًا.» كم فعلًا فيها، وما أنواعها؟', '[{"id":"a","text":"فعلٌ واحدٌ ماضٍ"},{"id":"b","text":"فعلان: «اقرأْ» أمرٌ، و«تزددْ» مضارعٌ"},{"id":"c","text":"فعلان ماضيان"},{"id":"d","text":"لا فعل فيها"}]'::jsonb, 'b', '«اقرأْ» فعلُ أمرٍ (طلبٌ)، و«تزددْ» مضارعٌ بدأ بالتاء؛ فالجملة فيها فعلان مختلفان في الزمن.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('23bf26c9-767d-5433-a696-fc9f2bd54a73', '3787ec36-4885-5684-b285-c05dd9206bb0', 'صرّف الفعل «وقفَ» في الأزمنة الثلاثة (ماضٍ، مضارع، أمر):', '[{"id":"a","text":"واقفٌ — وقوفٌ — موقفٌ"},{"id":"b","text":"يقفُ — قِفْ — وقفَ"},{"id":"c","text":"قِفْ — وقفَ — يقفُ"},{"id":"d","text":"وقفَ — يقفُ — قِفْ"}]'::jsonb, 'd', 'الترتيب الصحيح: ماضٍ «وقفَ» ثمّ مضارع «يقفُ» (حُذفت الواو) ثمّ أمر «قِفْ»؛ أمّا (أ) فأسماء، و(ب) و(ج) اختلّ فيهما الترتيب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

