INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f072d14a-0f27-5304-b9c7-26439819188b', 'c69ea5fd-902c-5988-86dc-747f4dd83c11', 'همزة القطع:', '[{"id":"a","text":"تُكتب وتُنطق دائمًا"},{"id":"b","text":"تسقط في النطق دائمًا"},{"id":"c","text":"لا تُكتب أبدًا"},{"id":"d","text":"تأتي في آخر الكلمة فقط"}]'::jsonb, 'a', 'همزة القطع تُكتب وتُنطق دائمًا في أوّل الكلام ووسطه، وتُرسم على الألف: «أَكلَ، أُمّ، إِلى».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e1e3272-af04-547b-85fd-604250f75b62', 'c69ea5fd-902c-5988-86dc-747f4dd83c11', 'كيف نرسم همزة الوصل في أوّل الكلمة؟', '[{"id":"a","text":"أَ (همزة فوق الألف)"},{"id":"b","text":"ا (ألفًا بلا همزة)"},{"id":"c","text":"إِ (همزة تحت الألف)"},{"id":"d","text":"ة (تاء مربوطة)"}]'::jsonb, 'b', 'همزة الوصل تُرسم ألفًا بلا همزةٍ «ا»، وتسقط في النطق عند الوصل بما قبلها، مثل «اكتبْ، اسم».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0c6d2d7c-b79c-5042-8d13-eabc0d327ba1', 'c69ea5fd-902c-5988-86dc-747f4dd83c11', 'ما الرسم الصحيح لتنوين الفتح في كلمة «كتاب»؟', '[{"id":"a","text":"كتابٌ"},{"id":"b","text":"كتابٍ"},{"id":"c","text":"كتابًا"},{"id":"d","text":"كتابْ"}]'::jsonb, 'c', 'تنوين الفتح يُرسم بفتحتين مع زيادة ألفٍ في آخر الاسم غالبًا: «كتابًا»؛ أمّا «كتابٌ» فتنوين ضمٍّ و«كتابٍ» تنوين كسر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a50f06bc-17d9-58fd-846f-3d3776a46a4d', 'c69ea5fd-902c-5988-86dc-747f4dd83c11', 'أيّ كلمةٍ تبدأ بهمزة قطعٍ؟', '[{"id":"a","text":"اكتبْ"},{"id":"b","text":"استمعَ"},{"id":"c","text":"ابن"},{"id":"d","text":"أَحمد"}]'::jsonb, 'd', '«أَحمد» تبدأ بهمزة قطعٍ تُنطق دائمًا (أَ)؛ أمّا «اكتبْ، استمعَ، ابن» فتبدأ بهمزة وصلٍ تسقط عند الوصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('126679c0-5189-5957-9eb2-c760f1822e28', 'c69ea5fd-902c-5988-86dc-747f4dd83c11', 'أيّ كلمةٍ لا نزيد فيها ألفًا عند تنوين الفتح؟', '[{"id":"a","text":"شجرة (شجرةً)، لانتهائها بتاءٍ مربوطة"},{"id":"b","text":"باب (بابًا)"},{"id":"c","text":"قلم (قلمًا)"},{"id":"d","text":"ولد (ولدًا)"}]'::jsonb, 'a', 'ما ينتهي بتاءٍ مربوطةٍ لا نزيد فيه ألفًا عند تنوين الفتح: «شجرةً» لا «شجرةًا»؛ أمّا «باب، قلم، ولد» فتأخذ الألف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

