INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03560a89-5ef4-5dd1-a89d-50295c86fecc', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'أين تُرسم همزة القطع المكسورة؟', '[{"id":"a","text":"تحت الألف: إِ"},{"id":"b","text":"فوق الألف: أَ"},{"id":"c","text":"بلا ألف"},{"id":"d","text":"في آخر الكلمة"}]'::jsonb, 'a', 'همزة القطع المكسورة تُرسم تحت الألف «إِ»، مثل «إِلى» و«إِبرة»؛ أمّا المفتوحة والمضمومة فتُرسمان فوق الألف.', 1)
