INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f2bdd39-6d5c-5908-bbb3-40302b3266f8', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'ما الرسم الصحيح لتنوين الضمّ في «قلم»؟', '[{"id":"a","text":"قلمًا"},{"id":"b","text":"قلمٌ"},{"id":"c","text":"قلمٍ"},{"id":"d","text":"قلمْ"}]'::jsonb, 'b', 'تنوين الضمّ يُرسم بضمّتين فوق آخر الحرف: «قلمٌ»؛ أمّا «قلمًا» فتنوين فتحٍ و«قلمٍ» تنوين كسر.', 2)
