INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45b2e8b1-984d-5335-9cb8-1e4c7f96aac4', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'أيّ كلمةٍ تبدأ بهمزة وصلٍ (تسقط عند الوصل)؟', '[{"id":"a","text":"أَرنب"},{"id":"b","text":"أُمّ"},{"id":"c","text":"اسم"},{"id":"d","text":"إِبرة"}]'::jsonb, 'c', '«اسم» تبدأ بهمزة وصلٍ تسقط عند الوصل («واسمُهُ» تُنطق وسمُهُ)؛ أمّا «أَرنب، أُمّ، إِبرة» فهمزاتها قطعٌ تُنطق دائمًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
