  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c5b2ae1-b2c1-5b74-a549-83013a729c4f', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'أكمل بتنوين الفتح الصحيح: «رأيتُ ___.»', '[{"id":"a","text":"طائرٌ"},{"id":"b","text":"طائرٍ"},{"id":"c","text":"طائرًا"},{"id":"d","text":"طائرْ"}]'::jsonb, 'c', 'المفعول به منوّنٌ بالفتح مع زيادة الألف: «رأيتُ طائرًا.»؛ أمّا «طائرٌ» فمرفوعٌ منوّنٌ بالضمّ لا يصلح مفعولًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b26ac56-e406-5631-beaa-2910d2cfa410', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'أيّ فعلٍ أمرٍ يبدأ بهمزة وصلٍ صحيحةٍ في الرسم؟', '[{"id":"a","text":"أُكتبْ"},{"id":"b","text":"اكتبْ"},{"id":"c","text":"إِكتبْ"},{"id":"d","text":"أَكتبْ"}]'::jsonb, 'b', 'فعل الأمر الثلاثيّ يبدأ بهمزة وصلٍ تُرسم ألفًا بلا همزة: «اكتبْ»؛ فلا نضع عليها همزةَ قطعٍ «أُكتبْ» أو «إِكتبْ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5bda9bf-79f4-51f9-a2f6-3f9f584ee5c3', 'f8803af5-f54d-5bc5-94fe-58767cfc2a15', 'ما الكلمة المكتوبة كتابةً صحيحةً عند تنوين الفتح؟', '[{"id":"a","text":"شكرً"},{"id":"b","text":"أهلً"},{"id":"c","text":"بابً"},{"id":"d","text":"شكرًا"}]'::jsonb, 'd', 'تنوين الفتح يحتاج ألفًا في آخره: «شكرًا»؛ أمّا «شكرً» و«أهلً» و«بابً» فنُسيت فيها ألف تنوين الفتح.', 6)
