INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73a4d23c-633d-5b61-8f7d-66ce5c146339', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'بأيّ حيلةٍ نكشف نوع الهمزة في أوّل الكلمة؟', '[{"id":"a","text":"نضع قبلها واوًا وننطقها: إن بقيت مسموعةً فقطعٌ، وإن سقطت فوصلٌ"},{"id":"b","text":"نعدّ حروف الكلمة"},{"id":"c","text":"ننظر إلى آخر الكلمة"},{"id":"d","text":"نضع تنوينًا في آخرها"}]'::jsonb, 'a', 'نصل الكلمة بما قبلها (نضع واوًا مثلًا): «وأَكلَ» تبقى الهمزة مسموعةً فهي قطعٌ، و«واكتبْ» تسقط فهي وصلٌ؛ فالنطق عند الوصل هو الفيصل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3d00dd3-1eb1-59ea-bcba-b442d1b22d59', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'أيّ مجموعةٍ كلُّها يبدأ بهمزة قطعٍ؟', '[{"id":"a","text":"اسم، ابن، اثنان"},{"id":"b","text":"أَحمد، إِبراهيم، أُسرة"},{"id":"c","text":"اكتبْ، اجلسْ، العبْ"},{"id":"d","text":"استمعَ، انطلقَ، اقتربَ"}]'::jsonb, 'b', '«أَحمد، إِبراهيم، أُسرة» همزاتها قطعٌ تُنطق دائمًا؛ أمّا مجموعتا الأمر والأفعال الخماسية «استمعَ» وأسماء «اسم، ابن» فهمزاتها وصل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7e7bcaa-e02f-5aae-84fe-c54eb32ef7ac', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'صحّح الخطأ في رسم تنوين الفتح: «قابلتُ صديقً».', '[{"id":"a","text":"صديقٌ"},{"id":"b","text":"صديقٍ"},{"id":"c","text":"صديقًا"},{"id":"d","text":"صديقْ"}]'::jsonb, 'c', 'نُسيت ألف تنوين الفتح؛ والصواب زيادتها: «قابلتُ صديقًا.»، والكلمة مفعولٌ به منوّنٌ بالفتح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bd15388-fe19-50cb-a683-7e3bcad39f79', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'أيّ كلمةٍ لا تأخذ ألفًا عند تنوين الفتح؟', '[{"id":"a","text":"ولد ← ولدًا"},{"id":"b","text":"قلم ← قلمًا"},{"id":"c","text":"باب ← بابًا"},{"id":"d","text":"ماء ← ماءً (همزة على ألف)"}]'::jsonb, 'd', 'ما ينتهي بهمزةٍ على ألفٍ لا نزيد بعده ألفًا: «ماءً» لا «ماءًا»؛ أمّا «ولد، قلم، باب» فتأخذ ألف تنوين الفتح.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('565802e0-46bd-5870-818b-e3036fe4e036', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'في «استمعَ الطفلُ إِلى أُمِّهِ.»، عيّن همزات القطع:', '[{"id":"a","text":"«استمعَ» فقط"},{"id":"b","text":"لا همزة قطع في الجملة"},{"id":"c","text":"«إِلى» و«أُمّ» (تُنطقان دائمًا)"},{"id":"d","text":"«الطفلُ» فقط"}]'::jsonb, 'c', '«إِلى» و«أُمّ» همزتاهما قطعٌ تُنطقان دائمًا؛ أمّا «استمعَ» فهمزتها وصلٌ تسقط عند الوصل («الطفلُ استمعَ» تُنطق الطفلُ سْتمعَ).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21ff7cd7-ba61-5bd8-8fd2-bf7a3ee10530', 'a2ddfceb-3548-592f-b767-bf3b7ee8ce83', 'قال تلميذٌ: «تنوين الفتح يحتاج ألفًا في كلّ الكلمات بلا استثناء». ما الصحيح؟', '[{"id":"a","text":"صحيحٌ دائمًا"},{"id":"b","text":"خطأ؛ لا ألف بعد التاء المربوطة (شجرةً) ولا بعد الهمزة على ألف (سماءً)"},{"id":"c","text":"صحيح، كلّ منوّنٍ بالفتح يأخذ ألفًا"},{"id":"d","text":"خطأ؛ تنوين الفتح لا ألف فيه أبدًا"}]'::jsonb, 'b', 'الخطأ الشائع: تعميم ألف تنوين الفتح. الأكثر يأخذ الألف «بابًا»، لكن لا ألف بعد التاء المربوطة «شجرةً» ولا بعد الهمزة على ألف «سماءً».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b541a011-f83e-552c-98e2-f0e1934d2a4e', '1f0ce821-1543-5673-aeeb-0d71757bc7a8', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الهمزة والتنوين', 2, 75, 15, 'practice', 'admin', 3)
