INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('136db51c-6857-5a30-bab9-5650203338e9', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'ما الفرق الأساسيّ بين همزة القطع وهمزة الوصل؟', '[{"id":"a","text":"القطع تُنطق دائمًا، والوصل تسقط عند الوصل"},{"id":"b","text":"القطع في الآخر والوصل في الأوّل"},{"id":"c","text":"لا فرق بينهما"},{"id":"d","text":"الوصل تُنطق دائمًا والقطع تسقط"}]'::jsonb, 'a', 'همزة القطع تُكتب وتُنطق دائمًا، أمّا همزة الوصل فتُنطق في أوّل الكلام وتسقط عند وصلها بما قبلها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1be72da3-f1da-565f-86d9-282c1f540bbb', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'اختر الكلمة المرسومة رسمًا صحيحًا بهمزة قطعٍ:', '[{"id":"a","text":"اَكلَ"},{"id":"b","text":"أَكلَ"},{"id":"c","text":"اكلَ"},{"id":"d","text":"إكلَ"}]'::jsonb, 'b', '«أَكلَ» فعلٌ ماضٍ ثلاثيٌّ يبدأ بهمزة قطعٍ مفتوحةٍ فوق الألف «أَ»؛ أمّا الرسوم الأخرى فخاطئةٌ في موضع الهمزة أو حركتها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2076d40-4189-52e7-8d24-43d4b28459e7', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'أكمل بتنوين الكسر الصحيح: «مررتُ بـ___.»', '[{"id":"a","text":"ولدًا"},{"id":"b","text":"ولدٌ"},{"id":"c","text":"ولدٍ"},{"id":"d","text":"ولدْ"}]'::jsonb, 'c', 'بعد حرف الجرّ «الباء» يأتي الاسم مجرورًا منوّنًا بالكسر: «مررتُ بولدٍ.»؛ أمّا «ولدًا» فتنوين فتحٍ و«ولدٌ» تنوين ضمّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f470c485-ee4d-5d6b-8354-4c1f62f178e5', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'أيّ كلمةٍ كُتبت كتابةً خاطئةً عند تنوين الفتح؟', '[{"id":"a","text":"قرأتُ كتابًا"},{"id":"b","text":"شربتُ ماءً"},{"id":"c","text":"زرعتُ شجرةً"},{"id":"d","text":"أكلتُ تمرً"}]'::jsonb, 'd', '«تمرً» نُسيت فيها ألف تنوين الفتح؛ والصواب «تمرًا»؛ أمّا «كتابًا» فصحيحة، و«ماءً» و«شجرةً» لا تأخذان ألفًا (همزة على ألف، وتاء مربوطة).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef5c3ae6-4724-590f-9bbd-351960ad351c', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'أيّ كلمةٍ تبدأ بهمزة وصلٍ؟', '[{"id":"a","text":"أُستاذ"},{"id":"b","text":"أَسد"},{"id":"c","text":"إِناء"},{"id":"d","text":"ابن"}]'::jsonb, 'd', '«ابن» تبدأ بهمزة وصلٍ تسقط عند الوصل؛ أمّا «أُستاذ، أَسد، إِناء» فهمزاتها قطعٌ تُنطق دائمًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('363c9123-6c33-57af-b4dc-d64ad5db9129', 'b541a011-f83e-552c-98e2-f0e1934d2a4e', 'في «اقرأْ كتابًا مفيدًا.»، عيّن الكلمة المبدوءة بهمزة وصلٍ والكلمة المنوّنة بالفتح:', '[{"id":"a","text":"الوصل «كتابًا»، والتنوين «اقرأْ»"},{"id":"b","text":"الوصل «اقرأْ»، والتنوين «كتابًا» (و«مفيدًا»)"},{"id":"c","text":"لا وصل ولا تنوين فيها"},{"id":"d","text":"الوصل «مفيدًا»، والتنوين «اقرأْ»"}]'::jsonb, 'b', '«اقرأْ» فعلُ أمرٍ يبدأ بهمزة وصلٍ، و«كتابًا» و«مفيدًا» منوّنان بالفتح مع ألفه؛ فاجتمع في الجملة الوصلُ والتنوين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', '1f0ce821-1543-5673-aeeb-0d71757bc7a8', 'arabic-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد الإملاء', 4, 300, 60, 'challenge', 'admin', 4)
