INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a2c62b8-d4fe-5f28-8879-89d7de2e456f', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'اقرأ: «إِنَّ المعلّمَ استدعى التلميذَ.» عيّن نوع الهمزتين في «إِنَّ» و«استدعى»:', '[{"id":"a","text":"«إِنَّ» قطعٌ (تُنطق دائمًا)، و«استدعى» وصلٌ (تسقط عند الوصل)"},{"id":"b","text":"كلتاهما قطع"},{"id":"c","text":"كلتاهما وصل"},{"id":"d","text":"«إِنَّ» وصلٌ، و«استدعى» قطعٌ"}]'::jsonb, 'a', '«إِنَّ» همزتها قطعٌ مكسورةٌ تُنطق دائمًا، و«استدعى» فعلٌ سداسيٌّ همزته وصلٌ تسقط عند الوصل («المعلّمُ استدعى» تُنطق المعلّمُ سْتدعى).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6ddffc1-9ea5-5089-a0ce-53c421dae498', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'صحّح الكلمات الثلاث في تنوين الفتح: «رأيتُ سماءًا صافيةً وطائرً».', '[{"id":"a","text":"سماءًا — صافية — طائرً (الكلّ صحيح)"},{"id":"b","text":"سماءً — صافيةً — طائرًا"},{"id":"c","text":"سماءً — صافيةًا — طائرً"},{"id":"d","text":"سماءًا — صافيةًا — طائرًا"}]'::jsonb, 'b', '«سماءً» همزةٌ على ألفٍ فلا تأخذ ألفًا زائدة، و«صافيةً» تاءٌ مربوطةٌ فلا ألف، و«طائرًا» تأخذ ألفَ تنوين الفتح؛ فالصواب: «سماءً صافيةً وطائرًا».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab278efc-0194-5cca-881b-488c0df7f65c', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'أيّ سطرٍ كلُّ همزاته قطعٌ صحيحةُ الرسم؟', '[{"id":"a","text":"اخذَ احمدُ ابرةً واختُهُ معه"},{"id":"b","text":"أخذَ احمدُ إبرةً واختُه معه"},{"id":"c","text":"أَخذَ أَحمدُ إِبرةً وأُختُهُ معه"},{"id":"d","text":"اَخذَ اَحمدُ اِبرةً واُختُه معه"}]'::jsonb, 'c', 'همزات القطع تُرسم على الألف بحركتها: «أَخذَ، أَحمد، إِبرة، أُخت»؛ فالسطر (ج) رسمها سليمًا، والبقيّة أهملت الهمزة أو وضعتها في غير موضعها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90fad209-363b-5f6f-aace-2873d5b7800d', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'في «اِجلسْ يا أَحمدُ واِقرأْ كتابًا.»، كم همزة وصلٍ وكم همزة قطعٍ؟', '[{"id":"a","text":"ثلاث همزات قطع"},{"id":"b","text":"لا همزة في الجملة"},{"id":"c","text":"قطعان ووصلٌ واحدة"},{"id":"d","text":"وصلان («اجلسْ، اقرأْ») وقطعٌ واحدةٌ («أَحمدُ»)"}]'::jsonb, 'd', '«اجلسْ» و«اقرأْ» فعلا أمرٍ همزتاهما وصلٌ، و«أَحمدُ» همزته قطعٌ تُنطق دائمًا؛ فالوصل اثنتان والقطع واحدة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd8bf93b-4044-51cb-b57c-28096b703a62', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'اقرأ: «ساعدْ أَخاكَ تجدْ عونًا.» أين الخطأ المحتمل في تنوين الفتح إن كُتب «عونً»؟', '[{"id":"a","text":"لا خطأ، «عونً» صحيحة"},{"id":"b","text":"يجب حذف التنوين كلِّه"},{"id":"c","text":"نُسيت ألف تنوين الفتح؛ الصواب «عونًا»"},{"id":"d","text":"يجب جعلها «عونٌ» بالضمّ"}]'::jsonb, 'c', '«عون» اسمٌ صحيح الآخر لا تاءَ مربوطةً فيه ولا همزةَ على ألف، فيأخذ ألفَ تنوين الفتح: «عونًا»؛ فكتابة «عونً» خطأٌ بنسيان الألف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59a2e317-c565-5dd5-91ab-7d3cf0b6508f', '7aacaf2a-47d8-500c-b8a9-74fd0df9cf1c', 'قال تلميذٌ: «كلّ فعلٍ ماضٍ ثلاثيٍّ يبدأ بهمزةٍ تكون همزتُهُ وصلًا». ما الأدقّ؟', '[{"id":"a","text":"خطأ؛ الماضي الثلاثيّ المبدوء بهمزةٍ همزتُهُ قطعٌ (أَكلَ، أَخذَ)، والوصلُ في أمر الثلاثيّ والماضي الخماسيّ/السداسيّ"},{"id":"b","text":"صحيحٌ دائمًا"},{"id":"c","text":"صحيح، كلّ ماضٍ همزته وصل"},{"id":"d","text":"خطأ؛ الأفعال لا تبدأ بهمزة"}]'::jsonb, 'a', 'الخطأ الشائع: الخلط في موضع الوصل. الماضي الثلاثيّ «أَكلَ، أَخذَ» همزته قطعٌ، أمّا همزة الوصل ففي أمر الثلاثيّ «اكتبْ» وفي ماضي الخماسيّ والسداسيّ «انطلقَ، استقبلَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

