INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3dcf8b28-3443-54e9-8a92-1aa0e7441589', '51861816-8742-5981-abc5-ad691f1b2efc', 'كيف تُرسم همزة القطع المضمومة في أوّل الكلمة؟', '[{"id":"a","text":"أُ (فوق الألف)"},{"id":"b","text":"إِ (تحت الألف)"},{"id":"c","text":"ا (بلا همزة)"},{"id":"d","text":"ـة (تاء مربوطة)"}]'::jsonb, 'a', 'همزة القطع المضمومة تُرسم فوق الألف «أُ»، مثل «أُمّ» و«أُسرة»؛ أمّا المكسورة فتحت الألف «إِ».', 1)
