INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df4d2662-f16e-53ed-98dd-0e554fd729ee', '51861816-8742-5981-abc5-ad691f1b2efc', 'ما الرسم الصحيح لتنوين الفتح في «درس»؟', '[{"id":"a","text":"درسٌ"},{"id":"b","text":"درسًا"},{"id":"c","text":"درسٍ"},{"id":"d","text":"درسْ"}]'::jsonb, 'b', 'تنوين الفتح يُرسم بفتحتين مع زيادة ألفٍ: «درسًا»؛ أمّا «درسٌ» فتنوين ضمٍّ و«درسٍ» تنوين كسر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e22a5477-a722-555b-abc0-0632be111d00', '51861816-8742-5981-abc5-ad691f1b2efc', 'أيّ كلمةٍ همزتها وصلٌ تسقط عند الوصل؟', '[{"id":"a","text":"أَمل"},{"id":"b","text":"إِناء"},{"id":"c","text":"أُفق"},{"id":"d","text":"انتبهَ"}]'::jsonb, 'd', '«انتبهَ» فعلٌ خماسيٌّ همزته وصلٌ تسقط عند الوصل؛ أمّا «أَمل، إِناء، أُفق» فهمزاتها قطعٌ تُنطق دائمًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a7e552d-d808-513b-86f7-54bb272351c2', '51861816-8742-5981-abc5-ad691f1b2efc', 'أيّ جملةٍ فيها خطأٌ في رسم تنوين الفتح؟', '[{"id":"a","text":"اشتريتُ قميصًا جديدًا."},{"id":"b","text":"قرأتُ قصّةً قصيرةً."},{"id":"c","text":"شربتُ عصيرً باردًا."},{"id":"d","text":"زرعتُ نخلةً عاليةً."}]'::jsonb, 'c', '«عصيرً» نُسيت فيها ألف تنوين الفتح؛ والصواب «عصيرًا»؛ أمّا «قصّةً، نخلةً» فبتاءٍ مربوطةٍ لا ألفَ فيها، و«قميصًا» صحيحة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c657d018-b67d-50ff-bdee-c298ad9c8252', '51861816-8742-5981-abc5-ad691f1b2efc', 'في «أَكلَ الطفلُ تفّاحةً واستراحَ.»، عيّن همزة القطع وهمزة الوصل:', '[{"id":"a","text":"لا همزة في الجملة"},{"id":"b","text":"كلتاهما قطع"},{"id":"c","text":"همزة القطع «أَكلَ»، وهمزة الوصل «استراحَ»"},{"id":"d","text":"همزة القطع «استراحَ»، وهمزة الوصل «أَكلَ»"}]'::jsonb, 'c', '«أَكلَ» ماضٍ ثلاثيٌّ همزته قطعٌ تُنطق دائمًا، و«استراحَ» ماضٍ سداسيٌّ همزته وصلٌ تسقط عند الوصل («الطفلُ استراحَ»).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cddfbc2-4779-5d23-b0de-53bda703027e', '51861816-8742-5981-abc5-ad691f1b2efc', 'اقرأ: «العبْ يا وَلدُ ثمّ كُلْ تمرًا.» ما الكلمة المبدوءة بهمزة وصلٍ والكلمة المنوّنة بالفتح؟', '[{"id":"a","text":"الوصل «تمرًا»، والتنوين «العبْ»"},{"id":"b","text":"الوصل «العبْ»، والتنوين «تمرًا»"},{"id":"c","text":"لا وصل ولا تنوين"},{"id":"d","text":"الوصل «كُلْ»، والتنوين «وَلدُ»"}]'::jsonb, 'b', '«العبْ» فعلُ أمرٍ ثلاثيٌّ يبدأ بهمزة وصلٍ، و«تمرًا» اسمٌ منوّنٌ بالفتح مع ألفه؛ أمّا «كُلْ» فأمرٌ بلا همزة وصلٍ ظاهرة في رسمه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

