INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c7b5a4e4-ca0a-547f-a1af-3724df21eb57', '519cff0e-abf9-587b-8e15-9a3608e1705d', 'كيف تُنطق التاء المربوطة عند الوقف (التوقّف على الكلمة)؟', '[{"id":"a","text":"تاءً صريحة"},{"id":"b","text":"هاءً ساكنة"},{"id":"c","text":"ألفًا"},{"id":"d","text":"لا تُنطق أبدًا"}]'::jsonb, 'b', 'التاء المربوطة (ة) تُنطق هاءً ساكنةً عند الوقف: «شجرة ← شجرهْ»، وتُنطق تاءً عند الوصل.', 1)
ON CONFLICT (id) DO UPDATE SET
