  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b4c0e71-361f-5d81-8635-fa520e6b42a2', '519cff0e-abf9-587b-8e15-9a3608e1705d', 'أيّ كلمةٍ تنتهي بتاءٍ مربوطة (ة)؟', '[{"id":"a","text":"بنت"},{"id":"b","text":"وردة"},{"id":"c","text":"كتبتْ"},{"id":"d","text":"وقت"}]'::jsonb, 'b', '«وردة» اسمٌ مؤنّثٌ ينتهي بتاءٍ مربوطةٍ تُنطق هاءً عند الوقف؛ أمّا «بنت» و«وقت» و«كتبتْ» فبتاءٍ مفتوحة.', 2)
ON CONFLICT (id) DO UPDATE SET
