  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('860be2a8-94ab-574d-9f54-876b854c7fdb', '519cff0e-abf9-587b-8e15-9a3608e1705d', 'التاء في آخر الفعل الماضي «لعبتْ» هي:', '[{"id":"a","text":"مفتوحة (ت)، وتاء الفعل مفتوحةٌ دائمًا"},{"id":"b","text":"مربوطة (ة)"},{"id":"c","text":"همزة"},{"id":"d","text":"ألف"}]'::jsonb, 'a', 'تاء التأنيث في آخر الفعل الماضي مفتوحةٌ دائمًا: «لعبتْ» لا «لعبةْ»؛ فلا تُرسم مربوطةً في الأفعال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f101bd2-7de1-56fc-8d05-f18215ff824b', '519cff0e-abf9-587b-8e15-9a3608e1705d', 'ما الحيلة الذهبيّة للتمييز بين التاءين؟', '[{"id":"a","text":"نعدّ الحروف"},{"id":"b","text":"ننظر إلى أوّل الكلمة"},{"id":"c","text":"نقف على الكلمة: هاءً ← مربوطة، تاءً ← مفتوحة"},{"id":"d","text":"نضع همزةً في آخرها"}]'::jsonb, 'c', 'الحيلة الذهبيّة هي الوقف على الكلمة: إن سمعتَها هاءً فالتاء مربوطة «وردهْ»، وإن بقيت تاءً فهي مفتوحة «بنتْ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6548e29b-7d16-598d-b9c2-444fc3da1988', '519cff0e-abf9-587b-8e15-9a3608e1705d', 'أيّ تمييزٍ صحيحٌ بين «اللعبة» و«لعبتْ»؟', '[{"id":"a","text":"كلتاهما بتاءٍ مربوطة"},{"id":"b","text":"كلتاهما بتاءٍ مفتوحة"},{"id":"c","text":"«اللعبة» فعلٌ و«لعبتْ» اسم"},{"id":"d","text":"«اللعبة» اسمٌ بتاءٍ مربوطة، و«لعبتْ» فعلٌ بتاءٍ مفتوحة"}]'::jsonb, 'd', '«اللعبة» اسمٌ مؤنّثٌ بتاءٍ مربوطةٍ تُنطق هاءً، و«لعبتْ» فعلٌ ماضٍ بتاءٍ مفتوحةٍ تبقى تاءً؛ فالنوع والرسم مختلفان.', 5)
ON CONFLICT (id) DO UPDATE SET
