INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b460d72-4531-5429-a58a-674b2bfa00a9', '83a7ec3c-2c11-5048-bdb0-93cb38a42c2d', 'إذا وقفتَ على «حقيبة» فماذا تسمع في آخرها؟', '[{"id":"a","text":"تاءً صريحة"},{"id":"b","text":"هاءً ساكنة (حقيبهْ)"},{"id":"c","text":"ألفًا"},{"id":"d","text":"نونًا"}]'::jsonb, 'b', '«حقيبة» تنتهي بتاءٍ مربوطةٍ تُنطق هاءً عند الوقف: «حقيبهْ»، وهذا دليلٌ على أنّها تاءٌ مربوطة.', 2)
