INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9da2d3c0-29d0-5e18-b4b9-dadeee3acfd5', '83a7ec3c-2c11-5048-bdb0-93cb38a42c2d', 'التاء في «كتبتُ الدرسَ» هي:', '[{"id":"a","text":"مربوطة (ة)"},{"id":"b","text":"همزة"},{"id":"c","text":"مفتوحة (ت)، وهي تاء الفاعل"},{"id":"d","text":"ألف"}]'::jsonb, 'c', '«كتبتُ» فعلٌ، والتاء فيه تاء الفاعل وهي مفتوحةٌ تبقى تاءً عند الوقف «كتبتْ»؛ فتاء الفعل لا تُرسم مربوطة.', 3)
