INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0f02104-aac9-5fe6-a7f2-8329c9906bbe', '88873e6e-1bd0-5369-a4c9-2a84d6e67f5f', 'إذا وقفتَ على «أخت» فسمعتَ «أختْ»، فالتاء فيها:', '[{"id":"a","text":"مربوطة (ة)"},{"id":"b","text":"همزة"},{"id":"c","text":"مفتوحة (ت)، لأنّها بقيت تاءً عند الوقف"},{"id":"d","text":"ألف"}]'::jsonb, 'c', '«أخت» وقفنا عليها فبقيت تاءً «أختْ» ولم تتحوّل هاءً، فهي تاءٌ مفتوحة؛ ولو كانت مربوطةً لقلنا «أخهْ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6af32478-ff4e-5360-8bbe-2028a3cc45eb', '88873e6e-1bd0-5369-a4c9-2a84d6e67f5f', 'ميّز بين «اللعبة» و«لعبتْ» من حيث النوع والتاء:', '[{"id":"a","text":"كلتاهما اسمٌ بتاءٍ مربوطة"},{"id":"b","text":"كلتاهما فعلٌ بتاءٍ مفتوحة"},{"id":"c","text":"«اللعبة» فعلٌ، و«لعبتْ» اسم"},{"id":"d","text":"«اللعبة» اسمٌ بتاءٍ مربوطة، و«لعبتْ» فعلٌ بتاءٍ مفتوحة"}]'::jsonb, 'd', '«اللعبة» اسمٌ مؤنّثٌ بتاءٍ مربوطةٍ تُنطق هاءً «اللعبهْ»، و«لعبتْ» فعلٌ ماضٍ بتاءٍ مفتوحةٍ تبقى تاءً؛ فالكلمتان تختلفان نوعًا ورسمًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2ee13fd-7c32-5613-b6db-78c4da05d1e0', '88873e6e-1bd0-5369-a4c9-2a84d6e67f5f', 'اقرأ: «زرعتْ المزارعةُ نبتةً.» عيّن التاء المفتوحة والتاء المربوطة:', '[{"id":"a","text":"كلتاهما مفتوحة"},{"id":"b","text":"المفتوحة في «نبتة»، والمربوطة في «زرعتْ»"},{"id":"c","text":"المفتوحة في «زرعتْ» (فعل)، والمربوطة في «نبتة» (اسم)"},{"id":"d","text":"لا تاء في الجملة"}]'::jsonb, 'c', '«زرعتْ» فعلٌ فتاؤه مفتوحةٌ (تبقى تاءً)، و«نبتة» اسمٌ مؤنّثٌ فتاؤه مربوطةٌ (تُنطق هاءً «نبتهْ»)؛ أمّا «المزارعة» فبتاءٍ مربوطةٍ أيضًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab54b163-e1c5-5af9-952f-fdb45aab7663', '88873e6e-1bd0-5369-a4c9-2a84d6e67f5f', 'قال تلميذٌ: «كلّ كلمةٍ تنتهي بصوت التاء تُكتب بتاءٍ مربوطة». ما الصحيح؟', '[{"id":"a","text":"صحيحٌ دائمًا"},{"id":"b","text":"خطأ؛ نقف على الكلمة: إن بقيت تاءً فهي مفتوحة (بنتْ، كتبتْ)، وإن صارت هاءً فهي مربوطة (وردهْ)"},{"id":"c","text":"صحيح، كلّ تاءٍ مربوطة"},{"id":"d","text":"خطأ؛ لا تأتي التاء في آخر الكلمة"}]'::jsonb, 'b', 'الخطأ الشائع: تعميم التاء المربوطة. الفيصل هو الوقف: «بنتْ» و«كتبتْ» تبقى تاءً فهي مفتوحة، و«وردهْ» تصير هاءً فهي مربوطة؛ فلا نكتبها كلَّها مربوطة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('243d9422-de24-5630-a742-321255e207f2', '83e3992c-d83f-557c-b38f-25b848b190a4', 'arabic-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): التاء المربوطة والمفتوحة', 2, 75, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e96b205-87db-563c-86c2-e46df673836b', '243d9422-de24-5630-a742-321255e207f2', 'ما علامة التاء المربوطة عند الوقف؟', '[{"id":"a","text":"تُنطق هاءً ساكنة"},{"id":"b","text":"تبقى تاءً صريحة"},{"id":"c","text":"تُنطق ألفًا"},{"id":"d","text":"تُحذف"}]'::jsonb, 'a', 'التاء المربوطة (ة) تُنطق هاءً ساكنةً عند الوقف: «مكتبة ← مكتبهْ»؛ وهذه أبرز علامةٍ تميّزها عن المفتوحة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e35e30c-d393-5763-94ee-c2718f211256', '243d9422-de24-5630-a742-321255e207f2', 'أيّ كلمةٍ كُتبت كتابةً صحيحة؟', '[{"id":"a","text":"كتبَة المعلّمُ"},{"id":"b","text":"بنة مجتهدة"},{"id":"c","text":"مدرسة كبيرة"},{"id":"d","text":"جلسهْ التلميذُ"}]'::jsonb, 'c', '«مدرسة» و«كبيرة» اسمان مؤنّثان بتاءٍ مربوطةٍ صحيحة؛ أمّا «كتبة المعلّم» (الصواب كتبَ بلا تاء) و«بنة» (الصواب بنت) و«جلسهْ» (الصواب جلسَ) فخاطئة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d9ca212-7863-516e-881f-87d0f22f72f3', '243d9422-de24-5630-a742-321255e207f2', 'حوّل الفعل إلى المؤنّث بالكتابة الصحيحة: «قرأَ ← ___ البنتُ.»', '[{"id":"a","text":"قرأة"},{"id":"b","text":"قرأهْ"},{"id":"c","text":"قرأتْ"},{"id":"d","text":"قرأا"}]'::jsonb, 'c', 'نضيف تاء التأنيث المفتوحة إلى الفعل: «قرأتْ البنتُ.»؛ فتاء الفعل مفتوحةٌ دائمًا، لا مربوطةً «قرأة» ولا هاءً «قرأهْ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cc270cd-e645-5f17-a5e7-7988cddbf5c6', '243d9422-de24-5630-a742-321255e207f2', 'أيّ كلمةٍ تنتهي بتاءٍ مفتوحة (ت)؟', '[{"id":"a","text":"زهرة"},{"id":"b","text":"نافذة"},{"id":"c","text":"سيّارة"},{"id":"d","text":"وقت"}]'::jsonb, 'd', '«وقت» اسمٌ ينتهي بتاءٍ مفتوحةٍ تبقى تاءً عند الوقف «وقتْ»؛ أمّا «زهرة، نافذة، سيّارة» فبتاءٍ مربوطةٍ تُنطق هاءً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a429b104-6905-534d-a9f8-ab48aade104b', '243d9422-de24-5630-a742-321255e207f2', 'اقرأ: «شاهدتُ نحلةً تجمعُ الرحيقَ.» ما نوع تاء «نحلة» وتاء «شاهدتُ»؟', '[{"id":"a","text":"كلتاهما مربوطة"},{"id":"b","text":"«نحلة» مربوطة (اسم)، و«شاهدتُ» مفتوحة (فعل، تاء الفاعل)"},{"id":"c","text":"«نحلة» مفتوحة، و«شاهدتُ» مربوطة"},{"id":"d","text":"كلتاهما مفتوحة (الاسم بتاءٍ مفتوحة)"}]'::jsonb, 'b', '«نحلة» اسمٌ مؤنّثٌ بتاءٍ مربوطةٍ (تُنطق هاءً «نحلهْ»)، و«شاهدتُ» فعلٌ وتاؤه تاء الفاعل مفتوحةٌ (تبقى تاءً)؛ فالنوعان مختلفان.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f652e7c-cf94-521e-a52d-b170dbf26fcc', '243d9422-de24-5630-a742-321255e207f2', 'أكمل باسمٍ بتاءٍ مفتوحة: «جلسَتْ ___ بجانبي.»', '[{"id":"a","text":"أختة"},{"id":"b","text":"أختهْ"},{"id":"c","text":"أخهْ"},{"id":"d","text":"أختي"}]'::jsonb, 'd', '«أخت» اسمٌ بتاءٍ مفتوحةٍ، ومع الإضافة إلى ياء المتكلّم تبقى التاء مفتوحة: «أختي»؛ فلا تُرسم مربوطةً «أختة» ولا هاءً «أختهْ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('83085632-cc96-5251-95de-7d76d598eeca', '83e3992c-d83f-557c-b38f-25b848b190a4', 'arabic-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد التاءين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
