INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f9b1da9-e7ba-5de8-9242-7e9402728a1b', '83085632-cc96-5251-95de-7d76d598eeca', 'اقرأ: «خرجتِ التلميذةُ من المدرسةِ ثمّ عادتْ.» كم تاءً مفتوحةً وكم مربوطة؟', '[{"id":"a","text":"مفتوحتان («خرجتِ، عادتْ» فعلان)، ومربوطتان («التلميذة، المدرسة»)"},{"id":"b","text":"أربع مفتوحات"},{"id":"c","text":"أربع مربوطات"},{"id":"d","text":"لا تاء في الجملة"}]'::jsonb, 'a', '«خرجتِ» و«عادتْ» فعلان فتاؤهما مفتوحةٌ (تبقى تاءً)، و«التلميذة» و«المدرسة» اسمان مؤنّثان بتاءٍ مربوطةٍ (تُنطق هاءً)؛ فمفتوحتان ومربوطتان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2b6d7cd-f3d4-5792-996b-377a4e93bbb9', '83085632-cc96-5251-95de-7d76d598eeca', 'صحّح الأخطاء في: «اللاعبت سجّلهْ هدفًا في المباراة».', '[{"id":"a","text":"اللاعبت سجّلهْ هدفًا في المباراة (صحيح)"},{"id":"b","text":"اللاعبة سجّلَ هدفًا في المباراة"},{"id":"c","text":"اللاعبه سجّلة هدفًا في المباراه"},{"id":"d","text":"اللاعبت سجّلة هدفًا في المبارات"}]'::jsonb, 'b', '«اللاعبة» اسمٌ مؤنّثٌ بتاءٍ مربوطة، و«سجّلَ» فعلٌ مذكّرٌ بلا تاءٍ (أو «سجّلتْ» للمؤنّث بتاءٍ مفتوحة)، و«المباراة» بتاءٍ مربوطة؛ فالصواب: «اللاعبة سجّلَ هدفًا في المباراة».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e31323e1-267d-5920-ac60-989be8589aa0', '83085632-cc96-5251-95de-7d76d598eeca', 'في «نَبْتةٌ» و«نبَتَتْ»، ما الفرق في نوع التاء وسببه؟', '[{"id":"a","text":"كلتاهما مربوطة لأنّهما من جذرٍ واحد"},{"id":"b","text":"كلتاهما مفتوحة"},{"id":"c","text":"«نبتة» اسمٌ فتاؤه مربوطة (نبتهْ)، و«نبتتْ» فعلٌ فتاؤه مفتوحة (تبقى تاءً)"},{"id":"d","text":"«نبتة» فعلٌ و«نبتتْ» اسم"}]'::jsonb, 'c', 'العبرة بنوع الكلمة لا بالجذر: «نبتة» اسمٌ مؤنّثٌ فتاؤه مربوطةٌ تُنطق هاءً، و«نبتتْ» فعلٌ ماضٍ فتاؤه مفتوحةٌ تبقى تاءً؛ فالاشتراك في الجذر لا يوحّد نوع التاء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ca829698-b041-572a-948c-f427ddb3f587', '83085632-cc96-5251-95de-7d76d598eeca', 'أيّ سطرٍ رسمُ تاءاته كلِّها صحيح؟', '[{"id":"a","text":"كتبتْ فاطمةُ رسالةً جميلةً إلى أختها"},{"id":"b","text":"كتبة فاطمتُ رسالتً جميلت إلى أختهة"},{"id":"c","text":"كتبتْ فاطمت رسالة جميلة إلى أخته"},{"id":"d","text":"كتبه فاطمة رسالت جميله إلى اختها"}]'::jsonb, 'a', '«كتبتْ» فعلٌ بتاءٍ مفتوحة، و«فاطمة، رسالة، جميلة» أسماءٌ وصفاتٌ مؤنّثةٌ بتاءٍ مربوطة، و«أختها» بتاءٍ مفتوحة؛ فالسطر (أ) صحيحٌ كلُّه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ee2166e-e03e-545a-a201-b329821f9010', '83085632-cc96-5251-95de-7d76d598eeca', 'اقرأ: «البنتُ المهذّبةُ ساعدتْ جدّتَها.» عيّن التاءات الثلاث وأنواعها:', '[{"id":"a","text":"«البنت» مربوطة، و«المهذّبة» مفتوحة، و«ساعدتْ» مربوطة"},{"id":"b","text":"الكلّ مربوطة"},{"id":"c","text":"الكلّ مفتوحة"},{"id":"d","text":"«البنت» مفتوحة، و«المهذّبة» مربوطة، و«ساعدتْ» مفتوحة، و«جدّتها» مربوطة"}]'::jsonb, 'd', '«البنت» اسمٌ بتاءٍ مفتوحة (تبقى تاءً)، و«المهذّبة» صفةٌ مؤنّثةٌ بتاءٍ مربوطة، و«ساعدتْ» فعلٌ بتاءٍ مفتوحة، و«جدّتها» اسمٌ مؤنّثٌ بتاءٍ مربوطة قبل الضمير؛ فلكلٍّ نوعُه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27057af2-512f-5997-b6c3-166f99a65494', '83085632-cc96-5251-95de-7d76d598eeca', 'قال تلميذٌ: «إذا أضفنا ضميرًا إلى الاسم المنتهي بتاءٍ مربوطةٍ بقيت مربوطةً في الرسم». ما الأدقّ؟', '[{"id":"a","text":"صحيحٌ دائمًا، لا تتغيّر"},{"id":"b","text":"صحيح، تبقى هاءً عند الإضافة"},{"id":"c","text":"خطأ؛ تُفتح التاء عند الإضافة فتصير مفتوحةً منطوقةً ومرسومةً تاءً: «جدّة ← جدّتها»"},{"id":"d","text":"خطأ؛ تُحذف التاء عند الإضافة"}]'::jsonb, 'c', 'عند إضافة الاسم المنتهي بتاءٍ مربوطةٍ إلى ضميرٍ تُنطق التاء وتُرسم مفتوحةً: «جدّة ← جدّتها»، «شجرة ← شجرتها»؛ لأنّها لم تعد في موضع الوقف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
