INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c47a44cb-7763-5d78-94a2-6c0f7394654d', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'أيّ كلمةٍ تنتهي بتاءٍ مربوطة (ة)؟', '[{"id":"a","text":"سبّورة"},{"id":"b","text":"بنت"},{"id":"c","text":"نامتْ"},{"id":"d","text":"بيت"}]'::jsonb, 'a', '«سبّورة» اسمٌ مؤنّثٌ بتاءٍ مربوطةٍ تُنطق هاءً عند الوقف «سبّورهْ»؛ أمّا «بنت، بيت، نامتْ» فبتاءٍ مفتوحة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9cf36e3-d400-5043-83a1-a19394d1e2d6', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'التاء في الفعل الماضي «شربتْ» هي:', '[{"id":"a","text":"مربوطة (ة)"},{"id":"b","text":"مفتوحة (ت)، وتاء الفعل مفتوحةٌ دائمًا"},{"id":"c","text":"همزة"},{"id":"d","text":"ألف"}]'::jsonb, 'b', '«شربتْ» فعلٌ ماضٍ، وتاء التأنيث فيه مفتوحةٌ دائمًا تبقى تاءً عند الوقف؛ فلا تُرسم مربوطةً «شربةْ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c7b33c50-4fea-5b54-8c47-9430f4fbc1ad', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'صحّح خطأ الرسم في «الطفله رسمهْ لوحةً».', '[{"id":"a","text":"الطفله رسمهْ لوحت"},{"id":"b","text":"الطفلت رسمت لوحه"},{"id":"c","text":"الطفلة رسمتْ لوحةً"},{"id":"d","text":"الطفلة رسمة لوحة"}]'::jsonb, 'c', '«الطفلة» اسمٌ مؤنّثٌ بتاءٍ مربوطة، و«رسمتْ» فعلٌ بتاءٍ مفتوحة، و«لوحة» اسمٌ بتاءٍ مربوطة؛ فالصواب: «الطفلة رسمتْ لوحةً».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af1ceb87-884b-5389-b3aa-1292ae515738', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'إذا وقفتَ على «وقت» سمعتَ «وقتْ»، فالتاء فيها:', '[{"id":"a","text":"مربوطة"},{"id":"b","text":"همزة"},{"id":"c","text":"ألف"},{"id":"d","text":"مفتوحة (ت)، لأنّها بقيت تاءً عند الوقف"}]'::jsonb, 'd', '«وقت» وقفنا عليها فبقيت تاءً «وقتْ» ولم تتحوّل هاءً، فهي تاءٌ مفتوحة؛ ولو كانت مربوطةً لقلنا «وقهْ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08bbfc55-7794-5c65-b5b9-d721716e41c1', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'اقرأ: «المعلّمةُ شرحتِ القاعدةَ.» عيّن التاء المربوطة والتاء المفتوحة:', '[{"id":"a","text":"كلتاهما مفتوحة"},{"id":"b","text":"المربوطة في «المعلّمة» و«القاعدة» (اسمان)، والمفتوحة في «شرحتِ» (فعل)"},{"id":"c","text":"المربوطة في «شرحتِ»، والمفتوحة في «المعلّمة»"},{"id":"d","text":"لا تاء في الجملة"}]'::jsonb, 'b', '«المعلّمة» و«القاعدة» اسمان مؤنّثان بتاءٍ مربوطةٍ (تُنطق هاءً)، و«شرحتِ» فعلٌ بتاءٍ مفتوحةٍ (تبقى تاءً)؛ فالاسمان مربوطان والفعل مفتوح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc3d0f2e-97e6-5df2-ba82-69292e1e8b34', '90f6ce51-4426-563a-ad14-dcde6f4afd90', 'أكمل بالكتابة الصحيحة عند إضافة الضمير: «أحضرتُ حقيبتي ثمّ فتحتُ ___.»', '[{"id":"a","text":"نافذتها (التاء تُفتح عند الإضافة)"},{"id":"b","text":"نافذةها"},{"id":"c","text":"نافذهْها"},{"id":"d","text":"نافذتـا"}]'::jsonb, 'a', '«نافذة» تاؤها مربوطة، لكن عند إضافتها إلى الضمير تُنطق وتُرسم مفتوحةً: «نافذتها»؛ لأنّها لم تعد في موضع الوقف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

